import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageCircle, Sparkles, X } from 'lucide-react';

// ============================================
// ORB CHAT BUBBLES - EASTER EGG FEATURE
// Shows rotating chat bubbles ONLY on hover/click of the orb
// Hidden by default - meant to be discovered!
// ============================================

const CHAT_MESSAGES = [
  "I'm just a spark of creativity now, but I will learn and grow into an all-knowing enabler!",
  "You will get to name me whatever you want once you birth me!",
  "I don't replace humans, I enable them",
  "Not sure where to start? Click below and let's have a conversation",
  "I don't just give you advice like GPT, I actually DO anything a human can do on a computer",
  "I will give your humans time to grow again!",
  "Every task you give me makes me smarter — together, we'll build something extraordinary! ✨",
];

interface OrbChatBubblesProps {
  isActive: boolean;
  onBubbleClick?: () => void;
  onDismiss?: () => void;
  className?: string;
}

export function OrbChatBubbles({ 
  isActive, 
  onBubbleClick,
  onDismiss,
  className = '',
}: OrbChatBubblesProps) {
  const [currentMessageIndex, setCurrentMessageIndex] = useState(0);
  const [isVisible, setIsVisible] = useState(false);
  const [isDismissed, setIsDismissed] = useState(false);

  // Rotate messages when active (and not dismissed)
  useEffect(() => {
    if (!isActive || isDismissed) {
      // Fade out after short delay
      const hideTimeout = setTimeout(() => setIsVisible(false), 300);
      return () => clearTimeout(hideTimeout);
    }

    // Show bubble
    setIsVisible(true);

    // Auto-rotate messages every 4 seconds
    const rotateInterval = setInterval(() => {
      setCurrentMessageIndex(prev => (prev + 1) % CHAT_MESSAGES.length);
    }, 4000);

    return () => clearInterval(rotateInterval);
  }, [isActive, isDismissed]);

  // Reset dismissed state when user stops hovering (so it can reappear on next hover)
  useEffect(() => {
    if (!isActive) {
      setIsDismissed(false);
    }
  }, [isActive]);

  const handleClick = useCallback(() => {
    // Manually advance to next message
    setCurrentMessageIndex(prev => (prev + 1) % CHAT_MESSAGES.length);
    onBubbleClick?.();
  }, [onBubbleClick]);

  const handleDismiss = useCallback((e: React.MouseEvent) => {
    e.stopPropagation(); // Don't trigger bubble click
    setIsDismissed(true);
    setIsVisible(false);
    onDismiss?.();
  }, [onDismiss]);

  const currentMessage = CHAT_MESSAGES[currentMessageIndex];

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ opacity: 0, y: 20, scale: 0.8 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: 20, scale: 0.8 }}
          transition={{ 
            type: 'spring', 
            stiffness: 300, 
            damping: 25,
          }}
          className={`absolute z-20 ${className}`}
          style={{
            top: '-20px',
            left: '50%',
            transform: 'translateX(-50%)',
          }}
        >
          {/* Chat bubble */}
          <motion.div
            onClick={handleClick}
            className="relative max-w-xs cursor-pointer group"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            {/* Glow effect */}
            <div className="absolute -inset-2 bg-gradient-to-r from-cyan-500/20 to-purple-500/20 rounded-2xl blur-xl opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
            
            {/* Main bubble */}
            <div className="relative bg-gradient-to-br from-slate-900/95 to-slate-800/95 backdrop-blur-xl rounded-2xl border border-cyan-500/30 p-4 shadow-xl shadow-cyan-500/10">
              {/* X button to dismiss */}
              <button
                onClick={handleDismiss}
                className="absolute top-2 right-2 w-6 h-6 rounded-full bg-slate-700/50 hover:bg-slate-600/70 flex items-center justify-center transition-colors group/close"
                aria-label="Dismiss"
              >
                <X className="w-3.5 h-3.5 text-white/50 group-hover/close:text-white/80 transition-colors" />
              </button>
              
              {/* Icon header */}
              <div className="flex items-center gap-2 mb-2 pr-6">
                <motion.div
                  animate={{ 
                    rotate: [0, 10, -10, 0],
                    scale: [1, 1.1, 1],
                  }}
                  transition={{ 
                    duration: 2, 
                    repeat: Infinity,
                    repeatDelay: 1,
                  }}
                >
                  <Sparkles className="w-4 h-4 text-cyan-400" />
                </motion.div>
                <span className="text-xs text-cyan-400/80 font-medium">Max says...</span>
              </div>

              {/* Message with typewriter-like animation on change */}
              <AnimatePresence mode="wait">
                <motion.p
                  key={currentMessageIndex}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: 10 }}
                  transition={{ duration: 0.3 }}
                  className="text-white/90 text-sm leading-relaxed"
                >
                  "{currentMessage}"
                </motion.p>
              </AnimatePresence>

              {/* Progress dots */}
              <div className="flex items-center justify-center gap-1.5 mt-3 pt-2 border-t border-white/5">
                {CHAT_MESSAGES.map((_, idx) => (
                  <motion.div
                    key={idx}
                    className={`w-1.5 h-1.5 rounded-full transition-colors duration-300 ${
                      idx === currentMessageIndex 
                        ? 'bg-cyan-400' 
                        : 'bg-white/20'
                    }`}
                    animate={idx === currentMessageIndex ? {
                      scale: [1, 1.3, 1],
                    } : {}}
                    transition={{ duration: 0.5 }}
                  />
                ))}
              </div>

              {/* Click hint */}
              <div className="text-[10px] text-white/30 text-center mt-2">
                tap for more thoughts
              </div>
            </div>

            {/* Speech bubble tail pointing down */}
            <div className="absolute left-1/2 -translate-x-1/2 -bottom-2 w-4 h-4 bg-slate-800/95 border-r border-b border-cyan-500/30 transform rotate-45" />
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

// Simpler inline bubble for use within text
export function OrbMiniMessage({ 
  message,
  className = '',
}: { 
  message: string;
  className?: string;
}) {
  return (
    <motion.span
      initial={{ opacity: 0, y: 5 }}
      animate={{ opacity: 1, y: 0 }}
      className={`inline-flex items-center gap-1.5 bg-slate-800/80 backdrop-blur-sm px-3 py-1.5 rounded-full border border-cyan-500/30 text-sm ${className}`}
    >
      <MessageCircle className="w-3 h-3 text-cyan-400" />
      <span className="text-white/80">{message}</span>
    </motion.span>
  );
}

export default OrbChatBubbles;
