import { motion } from 'framer-motion';
import { MessageCircle, Brain, Users, CheckCircle, Sparkles, Building2 } from 'lucide-react';

export interface Step {
  id: string;
  label: string;
  description: string;
  icon: 'chat' | 'brain' | 'org' | 'sparkles' | 'building';
}

interface StepProgressProps {
  steps: Step[];
  currentStepIndex: number;
  className?: string;
}

const iconMap = {
  chat: MessageCircle,
  brain: Brain,
  org: Users,
  sparkles: Sparkles,
  building: Building2,
};

export function StepProgress({ steps, currentStepIndex, className = '' }: StepProgressProps) {
  return (
    <div className={`w-full ${className}`}>
      {/* Clear header showing progress - more prominent on mobile */}
      <div className="text-center mb-3 sm:mb-4">
        <p className="text-sm sm:text-base text-cyan-400 font-medium">
          Step {currentStepIndex + 1} of {steps.length}
        </p>
        <p className="text-xs sm:text-sm text-white/70 mt-0.5 sm:hidden">
          {steps[currentStepIndex]?.label}
        </p>
        <p className="hidden sm:block text-sm text-cyan-400 font-medium">
          — {steps[currentStepIndex]?.label}
        </p>
      </div>
      
      {/* Mobile: Compact dots only */}
      <div className="flex sm:hidden items-center justify-center gap-2 mb-2">
        {steps.map((step, index) => {
          const isActive = index === currentStepIndex;
          const isCompleted = index < currentStepIndex;
          
          return (
            <div 
              key={step.id}
              className={`w-3 h-3 rounded-full transition-all ${
                isCompleted 
                  ? 'bg-cyan-500' 
                  : isActive 
                    ? 'bg-cyan-400 ring-2 ring-cyan-400/50 ring-offset-2 ring-offset-slate-900' 
                    : 'bg-slate-600'
              }`}
            />
          );
        })}
      </div>
      
      {/* Desktop: Full circles with labels */}
      <div className="hidden sm:flex items-center justify-between relative">
        {/* Connection line - visible base */}
        <div className="absolute top-6 left-0 right-0 h-1 bg-slate-600/50 rounded-full" />
        {/* Progress fill */}
        <div 
          className="absolute top-6 left-0 h-1 bg-gradient-to-r from-cyan-500 to-blue-500 transition-all duration-700 rounded-full shadow-lg shadow-cyan-500/30"
          style={{ width: `${(currentStepIndex / (steps.length - 1)) * 100}%` }}
        />
        
        {steps.map((step, index) => {
          const Icon = iconMap[step.icon];
          const isActive = index === currentStepIndex;
          const isCompleted = index < currentStepIndex;
          const isFuture = index > currentStepIndex;
          
          return (
            <div 
              key={step.id}
              className="flex flex-col items-center relative z-10"
            >
              {/* Step circle */}
              <motion.div
                initial={false}
                animate={{
                  scale: isActive ? 1.1 : 1,
                }}
                className="relative"
              >
                {/* Glow effect for active step */}
                {isActive && (
                  <>
                    <motion.div
                      animate={{
                        scale: [1, 1.3, 1],
                        opacity: [0.5, 0.2, 0.5],
                      }}
                      transition={{
                        duration: 2,
                        repeat: Infinity,
                        ease: 'easeInOut',
                      }}
                      className="absolute inset-0 rounded-full bg-cyan-500 blur-xl"
                    />
                    <motion.div
                      animate={{
                        scale: [1, 1.15, 1],
                      }}
                      transition={{
                        duration: 1.5,
                        repeat: Infinity,
                        ease: 'easeInOut',
                      }}
                      className="absolute inset-0 rounded-full border-2 border-cyan-400/50"
                    />
                  </>
                )}
                
                {/* FIXED: Future steps are now visible with border, not just dimmed */}
                {/* Responsive circle sizes: 40px on tablet, 48px on desktop */}
                <div
                  className={`w-10 h-10 md:w-12 md:h-12 rounded-full flex items-center justify-center transition-all duration-500 ${
                    isCompleted
                      ? 'bg-gradient-to-r from-cyan-500 to-blue-500 text-white'
                      : isActive
                        ? 'bg-gradient-to-r from-cyan-500 to-blue-500 text-white shadow-lg shadow-cyan-500/50'
                        : 'bg-slate-800/90 border-2 border-slate-500/80 text-slate-300'
                  }`}
                >
                  {isCompleted ? (
                    <CheckCircle className="w-5 h-5" />
                  ) : (
                    <Icon className={`w-5 h-5 ${isActive ? 'animate-pulse' : ''}`} />
                  )}
                </div>
              </motion.div>
              
              {/* Step label - FIXED: Future steps are readable, not invisible */}
              <motion.div
                initial={false}
                className="mt-3 text-center max-w-[100px] md:max-w-[140px]"
              >
                <div className={`text-xs font-semibold ${
                  isActive 
                    ? 'text-cyan-400' 
                    : isCompleted 
                      ? 'text-white/80' 
                      : 'text-slate-400'
                }`}>
                  Step {index + 1}
                </div>
                <div className={`text-[10px] md:text-xs mt-0.5 ${
                  isActive 
                    ? 'text-white font-medium' 
                    : isCompleted 
                      ? 'text-white/60' 
                      : 'text-slate-400'
                }`}>
                  {step.label}
                </div>
                
                {/* Active indicator */}
                {isActive && (
                  <motion.div
                    initial={{ opacity: 0, y: -5 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="mt-1 text-cyan-400 text-[10px] flex items-center justify-center gap-1"
                  >
                    <span className="inline-block w-1.5 h-1.5 bg-cyan-400 rounded-full animate-pulse" />
                    Current
                  </motion.div>
                )}
              </motion.div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

