// Extract learning from user messages
// Fix #7: Enhanced extraction - capture EVERYTHING from user messages
function extractFromUserMessage(message: string): LearnedInfo[] {
  const learned: LearnedInfo[] = [];
  const text = message.toLowerCase();
  const timestamp = Date.now();
  let idx = 0;
  
  // Company type / industry
  if (text.includes('dropship')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'company', text: 'Runs a dropshipping business', confidence: 0.95 });
  }
  if (text.includes('e-commerce') || text.includes('ecommerce') || text.includes('online store')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'company', text: 'E-commerce business', confidence: 0.95 });
  }
  if (text.includes('saas') || text.includes('software')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'company', text: 'SaaS/Software company', confidence: 0.9 });
  }
  if (text.includes('agency') || text.includes('consulting')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'company', text: 'Agency/Consulting business', confidence: 0.9 });
  }
  
  // Team size
  if (text.includes('just me') || text.includes('by myself') || text.includes('solo') || text.includes('one person')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Solo entrepreneur', confidence: 0.95 });
  }
  const teamMatch = text.match(/(\d+)\s*(people|employees|team members|person team|folks|staff)/);
  if (teamMatch) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: `Team of ${teamMatch[1]} people`, confidence: 0.95 });
  }
  
  // DEPARTMENTS - Fix #7: Capture burning departments (dev, customer care, etc)
  if (text.includes('dev') || text.includes('development') || text.includes('engineering') || text.includes('developers')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Has development/engineering team', confidence: 0.9 });
    if (text.includes('burn') || text.includes('overwhelm') || text.includes('struggling') || text.includes('behind') || text.includes('problem')) {
      learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Development is a burning issue', confidence: 0.95 });
    }
  }
  if (text.includes('customer care') || text.includes('customer service') || text.includes('support team') || text.includes('customer support')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Has customer support/care team', confidence: 0.9 });
    if (text.includes('burn') || text.includes('overwhelm') || text.includes('struggling') || text.includes('behind') || text.includes('problem')) {
      learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Customer support is a burning issue', confidence: 0.95 });
    }
  }
  if (text.includes('marketing')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Has marketing team/function', confidence: 0.9 });
  }
  if (text.includes('sales')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Has sales team/function', confidence: 0.9 });
  }
  if (text.includes('operations') || text.includes('ops')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Has operations team', confidence: 0.9 });
  }
  if (text.includes('finance') || text.includes('accounting') || text.includes('bookkeeping')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Has finance/accounting function', confidence: 0.9 });
  }
  if (text.includes('hr') || text.includes('human resources') || text.includes('people ops')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'team', text: 'Has HR function', confidence: 0.9 });
  }
  
  // Products/industry specifics
  if (text.includes('electronics') || text.includes('gadgets') || text.includes('tech products')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'company', text: 'Sells electronics and phone accessories', confidence: 0.9 });
  }
  if (text.includes('phone') || text.includes('accessories') || text.includes('cases')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'company', text: 'Phone accessories niche', confidence: 0.9 });
  }
  
  // Work patterns and challenges
  const hoursMatch = text.match(/(\d+)\s*hours?\s*(a day|daily|per day)?/);
  if (hoursMatch) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: `Works ${hoursMatch[1]} hour days`, confidence: 0.9 });
  }
  
  // Specific pain points
  if (text.includes('overwhelm') || text.includes('too much') || text.includes('can\'t keep up') || text.includes('drowning')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Feeling overwhelmed with workload', confidence: 0.9 });
  }
  if (text.includes('hiring') || text.includes('need to hire') || text.includes('looking for help')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Needs to scale team/hiring', confidence: 0.85 });
  }
  
  // Tasks mentioned
  if (text.includes('customer support') || text.includes('customer service') || text.includes('answering') || text.includes('tickets')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Handles customer support', confidence: 0.85 });
  }
  if (text.includes('orders') || text.includes('shipping') || text.includes('fulfillment')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Manages order fulfillment', confidence: 0.85 });
  }
  if (text.includes('email') || text.includes('emails') || text.includes('inbox')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Email management is time-consuming', confidence: 0.8 });
  }
  if (text.includes('meetings') || text.includes('calls')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'challenges', text: 'Many meetings/calls to manage', confidence: 0.8 });
  }
  
  // Goals
  const revenueMatch = text.match(/\$?([\d,]+k?m?)\s*(revenue|sales|monthly|per month|arr|mrr)?/i);
  if (revenueMatch && revenueMatch[1].length > 2) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'goals', text: `Revenue target: ${revenueMatch[1]}`, confidence: 0.9 });
  }
  if (text.includes('scale') || text.includes('grow') || text.includes('expand')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'goals', text: 'Looking to scale the business', confidence: 0.85 });
  }
  if (text.includes('automate') || text.includes('automation') || text.includes('efficient')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'goals', text: 'Wants to automate processes', confidence: 0.9 });
  }
  if (text.includes('free up time') || text.includes('more time') || text.includes('time back')) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'goals', text: 'Wants to free up personal time', confidence: 0.9 });
  }
  
  // Company name extraction
  const nameMatch = text.match(/(?:company|business|called|named?)\s+(?:is\s+)?["']?([A-Z][a-zA-Z0-9\s]+?)["']?(?:\.|,|$)/i);
  if (nameMatch && nameMatch[1].length > 2 && nameMatch[1].length < 50) {
    learned.push({ id: `u-${timestamp}-${idx++}`, category: 'company', text: `Company name: ${nameMatch[1].trim()}`, confidence: 0.95 });
  }
  
  return learned;
}

// Extract ONLY explicitly mentioned entities for MindMap (Fix 2 - accurate org chart)
function extractMindMapNodes(message: string, existingNodes: MindMapNode[]): MindMapNode[] {
  const newNodes: MindMapNode[] = [];
  const text = message.toLowerCase();
  const existingLabels = new Set(existingNodes.map(n => n.label.toLowerCase()));
  
  // Only add nodes for things EXPLICITLY mentioned
  
  // Team roles - only if explicitly mentioned
  if ((text.includes('marketing') || text.includes('marketer')) && !existingLabels.has('marketing')) {
    newNodes.push({ id: `node-marketing-${Date.now()}`, label: 'Marketing', type: 'department' });
  }
  if ((text.includes('sales') || text.includes('salesperson')) && !existingLabels.has('sales')) {
    newNodes.push({ id: `node-sales-${Date.now()}`, label: 'Sales', type: 'department' });
  }
  if ((text.includes('customer support') || text.includes('support team')) && !existingLabels.has('support')) {
    newNodes.push({ id: `node-support-${Date.now()}`, label: 'Support', type: 'department' });
  }
  if ((text.includes('developer') || text.includes('engineering') || text.includes('tech team')) && !existingLabels.has('engineering')) {
    newNodes.push({ id: `node-engineering-${Date.now()}`, label: 'Engineering', type: 'department' });
  }
  if ((text.includes('operations') || text.includes('ops')) && !existingLabels.has('operations')) {
    newNodes.push({ id: `node-ops-${Date.now()}`, label: 'Operations', type: 'department' });
  }
  if ((text.includes('finance') || text.includes('accounting')) && !existingLabels.has('finance')) {
    newNodes.push({ id: `node-finance-${Date.now()}`, label: 'Finance', type: 'department' });
  }
  
  // People - extract names if mentioned with roles
  const ceoMatch = text.match(/(?:ceo|founder|owner)\s+(?:is\s+)?([A-Z][a-z]+)/i);
  if (ceoMatch && !existingLabels.has(ceoMatch[1].toLowerCase())) {
    newNodes.push({ id: `node-${ceoMatch[1]}-${Date.now()}`, label: ceoMatch[1], type: 'people' });
  }
  
  // KPIs if mentioned
  if ((text.includes('revenue') || text.includes('sales goal')) && !existingLabels.has('revenue')) {
    newNodes.push({ id: `node-revenue-${Date.now()}`, label: 'Revenue', type: 'kpi' });
  }
  if ((text.includes('customer') && text.includes('growth')) && !existingLabels.has('customer growth')) {
    newNodes.push({ id: `node-growth-${Date.now()}`, label: 'Customer Growth', type: 'kpi' });
  }
  
  return newNodes;
}

type OnboardingStep = 'welcome' | 'chat' | 'learning' | 'summary';

// Demo message limit - push to signup after this
const MAX_DEMO_MESSAGES = 10;

// Component to show what Max has learned with fly-in animation
function LearnedInfoPanel({ 
  learnedInfo, 
  newItemIds = [],
  panelRef,
}: { 
  learnedInfo: LearnedInfo[]; 
  newItemIds?: string[];
  panelRef?: (el: HTMLDivElement | null) => void;
}) {
  const categoryIcons: Record<string, string> = {
    company: '🏢',
    team: '👥',
    goals: '🎯',
    challenges: '⚡',
    personal: '👤',
  };
  
  const categoryLabels: Record<string, string> = {
    company: 'About Your Business',
    team: 'Your Team',
    goals: 'Goals & Ambitions',
    challenges: 'Challenges',
    personal: 'About You',
  };
  
  // Group by category
  const grouped = learnedInfo.reduce((acc, item) => {
    const cat = item.category || 'company';
    if (!acc[cat]) acc[cat] = [];
    acc[cat].push(item);
    return acc;
  }, {} as Record<string, LearnedInfo[]>);
  
  return (
    <motion.div
      ref={panelRef}
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="bg-slate-900/60 backdrop-blur-xl rounded-3xl border-2 border-cyan-500/30 p-5 shadow-lg shadow-cyan-500/10"
    >
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <Brain className="w-5 h-5 text-cyan-400" />
          <h3 className="text-white font-semibold">What I Learned</h3>
        </div>
        {learnedInfo.length > 0 && (
          <motion.span 
            key={learnedInfo.length}
            initial={{ scale: 1.3, color: '#22D3EE' }}
            animate={{ scale: 1, color: '#94A3B8' }}
            className="text-sm font-medium bg-cyan-500/20 px-2 py-0.5 rounded-full"
          >
            {learnedInfo.length} insight{learnedInfo.length !== 1 ? 's' : ''}
          </motion.span>
        )}
      </div>
      
      {learnedInfo.length === 0 ? (
        <div className="text-center py-6">
          <div className="text-white/30 text-sm">
            Start talking — I'll show what I learn here
          </div>
          <div className="mt-2 flex justify-center gap-1">
            <div className="w-2 h-2 bg-cyan-500/30 rounded-full animate-pulse" />
            <div className="w-2 h-2 bg-cyan-500/30 rounded-full animate-pulse" style={{ animationDelay: '150ms' }} />
            <div className="w-2 h-2 bg-cyan-500/30 rounded-full animate-pulse" style={{ animationDelay: '300ms' }} />
          </div>
        </div>
      ) : (
        <div className="space-y-4 max-h-[350px] overflow-y-auto pr-2 scrollbar-thin scrollbar-thumb-cyan-500/20">
          {Object.entries(grouped).map(([category, items]) => (
            <motion.div 
              key={category}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ duration: 0.3 }}
            >
              <div className="flex items-center gap-2 mb-2 border-b border-white/5 pb-1">
                <span className="text-lg">{categoryIcons[category] || '📝'}</span>
                <span className="text-xs text-cyan-400/80 uppercase tracking-wider font-semibold">
                  {categoryLabels[category] || category}
                </span>
              </div>
              <ul className="space-y-2 pl-1">
                {items.map((item, idx) => {
                  const isNew = newItemIds.includes(item.id);
                  return (
                    <motion.li
                      key={item.id}
                      initial={isNew ? { 
                        opacity: 0, 
                        x: -50, 
                        scale: 0.8,
                        backgroundColor: 'rgba(6, 182, 212, 0.4)' 
                      } : { opacity: 1, x: 0 }}
                      animate={{ 
                        opacity: 1, 
                        x: 0, 
                        scale: 1,
                        backgroundColor: 'rgba(6, 182, 212, 0)' 
                      }}
                      transition={{ 
                        delay: isNew ? 0.3 + idx * 0.1 : 0,
                        duration: 0.6,
                        type: isNew ? 'spring' : 'tween',
                        stiffness: 200,
                        damping: 20,
                      }}
                      className="flex items-start gap-2 py-1.5 px-2 rounded-lg"
                    >
                      <motion.div
                        initial={isNew ? { scale: 0, rotate: -180 } : { scale: 1 }}
                        animate={{ scale: 1, rotate: 0 }}
                        transition={{ 
                          delay: isNew ? 0.5 + idx * 0.1 : 0,
                          type: 'spring',
                          stiffness: 300,
                        }}
                      >
                        <CheckCircle className="w-4 h-4 text-cyan-400 mt-0.5 flex-shrink-0" />
                      </motion.div>
                      <span className="text-sm text-white/90">
                        {isNew ? (
                          <TypewriterText text={item.text} speed={25} cursor={false} />
                        ) : (
                          item.text
                        )}
                      </span>
                    </motion.li>
                  );
                })}
              </ul>
            </motion.div>
          ))}
        </div>
      )}
    </motion.div>
  );
}

export function MaxOnboardingPage() {
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState<OnboardingStep>('welcome');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  // MindMap starts EMPTY - only shows what user actually mentions (Fix 2)
  const [mindMapNodes, setMindMapNodes] = useState<MindMapNode[]>([]);
  // Context scores start at 0% - must be earned (Fix 4)
  const [contextScores, setContextScores] = useState<ContextScore[]>([
    { id: 'score-company', label: 'Company', category: 'company', score: 0 },
    { id: 'score-team', label: 'Team', category: 'department', score: 0 },
    { id: 'score-goals', label: 'Goals', category: 'user', score: 0 },
  ]);
  const [voiceEnabled, setVoiceEnabled] = useState(true);
  const [learnedInfo, setLearnedInfo] = useState<LearnedInfo[]>([]);
  const [newLearnedIds, setNewLearnedIds] = useState<string[]>([]);
  const [companyId, setCompanyId] = useState<string | null>(null);
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [orbIngestPulse, setOrbIngestPulse] = useState(false);
  const [orbReleasePulse, setOrbReleasePulse] = useState(false);
  
  // State for orb interaction on welcome screen
  const [orbHovered, setOrbHovered] = useState(false);
  const [orbClicked, setOrbClicked] = useState(false);
  const [bubbleDismissed, setBubbleDismissed] = useState(false);
  
  const userMessageCountRef = useRef(0);
  const [demoLimitReached, setDemoLimitReached] = useState(false);
  const orbRef = useRef<MaxOrbRef>(null);
  const notesPanelRef = useRef<HTMLDivElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);
  const dataFlowRef = useRef<DataFlowAnimationRef | null>(null);

  // Update step based on learning progress
  useEffect(() => {
    if (learnedInfo.length >= 8 && currentStepIndex === 0) {
      // Enough learning to move to step 2
      setCurrentStepIndex(1);
    }
    if (learnedInfo.length >= 12 && currentStepIndex === 1) {
      // Ready for deployment
      setCurrentStepIndex(2);
    }
  }, [learnedInfo.length, currentStepIndex]);

  // Initialize company session
  useEffect(() => {
    if (currentStep === 'chat' && !companyId) {
      createCompany('Onboarding Session')
        .then(company => {
          setCompanyId(company.id);
          console.log('[Max] Company session created:', company.id);
        })
        .catch(err => {
          console.error('[Max] Failed to create company session:', err);
          // Continue anyway - we'll handle errors in chat
        });
    }
  }, [currentStep, companyId]);

  // Set up data flow refs when they're available
  useEffect(() => {
    if (dataFlowRef.current && orbRef.current?.getElement) {
      const orbElement = orbRef.current.getElement();
      if (orbElement) {
        dataFlowRef.current.setOrbRef(orbElement);
      }
    }
    if (dataFlowRef.current && notesPanelRef.current) {
      dataFlowRef.current.setNotesRef(notesPanelRef.current);
    }
    if (dataFlowRef.current && chatContainerRef.current) {
      dataFlowRef.current.setChatRef(chatContainerRef.current);
    }
  }, [currentStep]);

  // Calculate orb growth level based on learned info (Fix 3)
  const orbGrowthLevel = Math.min(learnedInfo.length, 10);

  // Handle orb animations
  const handleOrbIngest = useCallback(() => {
    setOrbIngestPulse(true);
    orbRef.current?.triggerIngest?.();
    setTimeout(() => setOrbIngestPulse(false), 600);
  }, []);

  const handleOrbRelease = useCallback(() => {
    setOrbReleasePulse(true);
    orbRef.current?.triggerRelease?.();
    setTimeout(() => setOrbReleasePulse(false), 600);
  }, []);

  // Handle message - connects to REAL Claude AI (Fix 1)
  const handleMessage = useCallback(async (content: string) => {
    // Check if demo limit reached
    if (demoLimitReached) {
      console.log('[Max] Demo limit already reached, ignoring message');
      return;
    }
    
    console.log('[Max] User message received:', content);
    
    userMessageCountRef.current += 1;
    
    // Check if this message hits the limit
    if (userMessageCountRef.current >= MAX_DEMO_MESSAGES) {
      console.log('[Max] Demo limit reached after this message');
      // We'll set the flag after the response comes back
    }
    
    // On first message, add "You" node to mindmap (Fix 2 - accurate org chart)
    if (userMessageCountRef.current === 1) {
      setMindMapNodes([{ id: 'node-you', label: 'You', type: 'people' }]);
    }

    // Add user message
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content,
      timestamp: new Date(),
    };
    setMessages(prev => [...prev, userMsg]);
    
    // 🚀 TRIGGER DATA FLOW ANIMATION: Message flies to orb
    setTimeout(() => {
      dataFlowRef.current?.triggerMessageToOrb(content);
    }, 100);
    
    // Extract learning from user message immediately
    const userLearning = extractFromUserMessage(content);
    if (userLearning.length > 0) {
      // Delay adding learned info until after the animation
      setTimeout(() => {
        setLearnedInfo(prev => {
          // Avoid duplicate learnings
          const existingTexts = new Set(prev.map(l => l.text.toLowerCase()));
          const unique = userLearning.filter(l => !existingTexts.has(l.text.toLowerCase()));
          // Track new IDs for animation
          const newIds = unique.map(l => l.id);
          setNewLearnedIds(prevIds => [...prevIds, ...newIds]);
          
          // 🚀 TRIGGER INSIGHT FLOW: Each insight flies from orb
          unique.forEach((item, idx) => {
            setTimeout(() => {
              dataFlowRef.current?.triggerInsightFromOrb(item.text);
            }, idx * 400);
          });
          
          // Clear new IDs after animation
          setTimeout(() => {
            setNewLearnedIds(prevIds => prevIds.filter(id => !newIds.includes(id)));
          }, 3000);
          return [...prev, ...unique];
        });
      }, 800); // Wait for message-to-orb animation
    }
    
    setIsTyping(true);

    try {
      // Build conversation history for context
      const conversationHistory = messages.map(m => ({
        role: m.role as 'user' | 'assistant',
        content: m.content,
      }));

      // Call real Claude AI backend (Fix 1 & 2)
      const response = await chatWithMax(
        companyId || 'temp-session',
        content,
        conversationHistory,
        learnedInfo
      );

      setIsTyping(false);

      // Add Max's response with typewriter animation
      const maxMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: response.response,
        timestamp: new Date(),
        isNew: true, // Triggers typewriter animation
      };
      setMessages(prev => [...prev, maxMsg]);
      
      // Clear the isNew flag after animation would complete
      setTimeout(() => {
        setMessages(prev => prev.map(m => 
          m.id === maxMsg.id ? { ...m, isNew: false } : m
        ));
      }, response.response.length * 30 + 500);

      // Update learned info (Fix 4) with animation tracking
      if (response.learned_info && response.learned_info.length > 0) {
        const newIds = response.learned_info.map(l => l.id);
        setNewLearnedIds(prev => [...prev, ...newIds]);
        setLearnedInfo(prev => [...prev, ...response.learned_info!]);
        
        // 🚀 TRIGGER INSIGHT FLOW for backend insights
        response.learned_info.forEach((item, idx) => {
          setTimeout(() => {
            dataFlowRef.current?.triggerInsightFromOrb(item.text);
          }, 200 + idx * 400);
        });
        
        // Clear new IDs after animation
        setTimeout(() => {
          setNewLearnedIds(prev => prev.filter(id => !newIds.includes(id)));
        }, 3000);
      }

      // Update mind map with ONLY nodes explicitly mentioned in conversation (Fix 2)
      // Extract from user's message directly - don't trust backend suggestions blindly
      const userMentionedNodes = extractMindMapNodes(content, mindMapNodes);
      if (userMentionedNodes.length > 0) {
        setMindMapNodes(prev => [...prev, ...userMentionedNodes]);
      }
      
      // Also check backend suggestions but filter them more strictly
      if (response.suggested_nodes && response.suggested_nodes.length > 0) {
        // Only add if the label was actually in the user's message
        const contentLower = content.toLowerCase();
        const strictlyRelevant = response.suggested_nodes.filter(n => 
          contentLower.includes(n.label.toLowerCase()) ||
          contentLower.includes(n.label.toLowerCase().replace(/\s+/g, ''))
        );
        
        if (strictlyRelevant.length > 0) {
          const newNodes: MindMapNode[] = strictlyRelevant.map(n => ({
            id: n.id,
            label: n.label,
            type: n.type as MindMapNode['type'],
          }));
          setMindMapNodes(prev => {
            const existingLabels = new Set(prev.map(n => n.label.toLowerCase()));
            const unique = newNodes.filter(n => !existingLabels.has(n.label.toLowerCase()));
            return [...prev, ...unique];
          });
        }
      }

      // Update context scores based on learned info (Fix 4 - earned, not inflated)
      updateContextScores(response.learned_info || [], userLearning);

      // Check if demo limit reached - add signup CTA message
      if (userMessageCountRef.current >= MAX_DEMO_MESSAGES) {
        setTimeout(() => {
          const signupMsg: Message = {
            id: `signup-cta-${Date.now()}`,
            role: 'assistant',
            content: `🎉 Wow, I've already learned so much about your business!\n\nThis is just a taste of what an AI Enabler can do. Imagine having this level of understanding across your entire organization — every employee with their own trained AI assistant.\n\n**Ready to transform your company?**\n\nSign up now to:\n• Deploy AI Enablers across all departments\n• Train them on your specific processes\n• Get 24/7 intelligent support for every team member\n\n👉 Let's set up your full iEnable deployment!`,
            timestamp: new Date(),
            isNew: true,
          };
          setMessages(prev => [...prev, signupMsg]);
          setDemoLimitReached(true);
        }, 1500); // Delay so Max's response appears first
      }

      // Check if we should transition to learning view
      // Transition after sufficient learning (10+ items) or explicit completion signal
      if (learnedInfo.length >= 10 || response.response.toLowerCase().includes('i have a good understanding')) {
        console.log('[Max] Sufficient learning achieved, will transition soon...');
        // Don't auto-transition - let user continue until they're ready
      }

    } catch (error) {
      console.error('[Max] Chat error:', error);
      setIsTyping(false);
      
      // Show error message
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: "I'm having a moment - could you say that again?",
        timestamp: new Date(),
      };
      setMessages(prev => [...prev, errorMsg]);
    }
  }, [companyId, messages, learnedInfo, demoLimitReached]);

  // Update context scores based on learned info (Fix 4 - honest reflection)
  const updateContextScores = (backendLearned: LearnedInfo[], userLearned: LearnedInfo[]) => {
    const allLearned = [...backendLearned, ...userLearned];
    if (allLearned.length === 0) return;
    
    setContextScores(prev => {
      const scores = [...prev];
      
      allLearned.forEach(item => {
        // Map learning categories to score categories
        let scoreCategory: 'company' | 'department' | 'user';
        let scoreLabel: string;
        
        if (item.category === 'company') {
          scoreCategory = 'company';
          scoreLabel = 'Company';
        } else if (item.category === 'team') {
          scoreCategory = 'department';
          scoreLabel = 'Team';
        } else if (item.category === 'goals' || item.category === 'challenges') {
          scoreCategory = 'user';
          scoreLabel = 'Goals';
        } else {
          scoreCategory = 'company';
          scoreLabel = 'Company';
        }
        
        const existingIndex = scores.findIndex(s => s.category === scoreCategory);
        if (existingIndex >= 0) {
          // Increment by 8-12% per learning (realistic progress)
          const increment = 8 + Math.floor(item.confidence * 4);
          scores[existingIndex] = {
            ...scores[existingIndex],
            score: Math.min(100, scores[existingIndex].score + increment),
          };
        }
      });
      
      return scores;
    });
  };

  // Welcome screen - ENHANCED with all 7 improvements
  if (currentStep === 'welcome') {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-900 flex flex-col items-center justify-start p-4 pt-8 md:pt-16 overflow-x-hidden relative">
        {/* Enhancement #6: Subtle background connections */}
        <BackgroundConnections 
          intensity={0.25} 
          className="opacity-60"
        />
        
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.6 }}
          className="max-w-4xl w-full text-center px-2 relative z-10"
        >
          {/* THE SPINNING CIRCLE ORB - positioned higher on page */}
          {/* This is now the main visual - moved up with flex-col + justify-start */}
          <div className="relative -mt-4 md:-mt-8">
            <MaxOrb 
              isThinking={false} 
              growthLevel={0}
              onHover={setOrbHovered}
              onClick={() => {
                setOrbClicked(prev => !prev);
                setBubbleDismissed(false); // Reset dismiss on click
              }}
              showInteractionHint={true}
            />
            {/* EASTER EGG: Chat bubbles only on hover/click - not shown by default */}
            {/* User can dismiss with X button */}
            <OrbChatBubbles 
              isActive={(orbHovered || orbClicked) && !bubbleDismissed}
              onDismiss={() => setBubbleDismissed(true)}
              className="top-[-60px]"
            />
          </div>
          
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3, duration: 0.6 }}
            className="mt-4 md:mt-8"
          >
            {/* Enhancement #1: BIGGER INTRO MESSAGE */}
            <h1 className="text-4xl md:text-6xl font-bold text-white mb-4 md:mb-6">
              Hello, I'm <span className="bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent">Max</span>
            </h1>
            <p className="text-xl md:text-3xl text-white/90 mb-4 md:mb-6 font-medium">
              Your AI Business <EnableTextBig>Enabler</EnableTextBig>
            </p>
            
            {/* Enhancement #1: New larger, rewritten welcome text */}
            <div className="text-white/80 max-w-3xl mx-auto mb-8 md:mb-10 px-4">
              <p className="text-lg md:text-xl leading-relaxed">
                Think of me as your new <span className="text-cyan-400 font-semibold">AI Employee</span> who{' '}
                <EnableText size="lg">Enables</EnableText> every employee to{' '}
                <span className="text-emerald-400 font-bold">10x their productivity!</span>
              </p>
              <p className="text-base md:text-lg mt-4 text-white/70 leading-relaxed">
                Every employee gets their own smart AI assistant — trained on{' '}
                <span className="text-cyan-300">your business</span> and{' '}
                <span className="text-cyan-300">their department</span>, ready to work{' '}
                <span className="text-purple-400 font-medium">24/7</span>.
              </p>
            </div>
            
            {/* Enhancement #7: Context before "Begin Onboarding" */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.6, duration: 0.5 }}
              className="bg-slate-900/50 backdrop-blur-sm rounded-2xl border border-cyan-500/20 p-4 md:p-6 max-w-2xl mx-auto mb-6"
            >
              <div className="flex items-start gap-3 text-left">
                <Sparkles className="w-5 h-5 text-cyan-400 mt-1 flex-shrink-0" />
                <p className="text-white/80 text-sm md:text-base leading-relaxed">
                  Let's start with learning about you and your business, and then we can build you an{' '}
                  <span className="text-cyan-400 font-medium">AI Org Chart example</span> so you can roll out at your own pace!
                </p>
              </div>
            </motion.div>
            
            <button
              onClick={() => setCurrentStep('chat')}
              className="bg-gradient-to-r from-cyan-500 to-blue-500 text-white font-semibold px-8 md:px-12 py-4 md:py-5 rounded-2xl hover:shadow-2xl hover:shadow-cyan-500/30 transition-all active:scale-95 inline-flex items-center gap-2 md:gap-3 text-base md:text-lg"
            >
              Begin Onboarding
              <ArrowRight className="w-5 h-5 md:w-6 md:h-6" />
            </button>
          </motion.div>
        </motion.div>
      </div>
    );
  }

  // Chat interface with data flow animations
  if (currentStep === 'chat') {
    return (
      <DataFlowAnimation
        onOrbIngest={handleOrbIngest}
        onOrbRelease={handleOrbRelease}
      >
        {(animationRef) => {
          // Store ref for use in handleMessage
          dataFlowRef.current = animationRef;
          
          return (
            <div className="min-h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-900 p-3 md:p-8 overflow-x-hidden">
              <div className="max-w-7xl mx-auto w-full">
                {/* Step Progress Indicator */}
                <motion.div
                  initial={{ opacity: 0, y: -20 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="mb-6 md:mb-8 bg-slate-900/40 backdrop-blur-xl rounded-2xl md:rounded-3xl border border-cyan-500/20 p-4 md:p-6"
                >
                  <StepProgress 
                    steps={MAX_ONBOARDING_STEPS} 
                    currentStepIndex={currentStepIndex}
                  />
                </motion.div>

                {/* Header */}
                <motion.div
                  initial={{ opacity: 0, y: -20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.1 }}
                  className="mb-4 md:mb-6"
                >
                  <h1 className="text-2xl md:text-4xl font-bold text-white mb-1 md:mb-2">
                    Onboarding with Max
                  </h1>
                  <p className="text-white/60 text-sm md:text-base">
                    Building understanding of your organization
                    {learnedInfo.length > 0 && (
                      <span className="ml-2 text-cyan-400">
                        • {learnedInfo.length} insight{learnedInfo.length !== 1 ? 's' : ''} learned
                      </span>
                    )}
                  </p>
                </motion.div>

                {/* Mobile-first layout: stack vertically on mobile */}
                <div className="flex flex-col lg:grid lg:grid-cols-3 gap-4 md:gap-6">
                  {/* Orb - shown first on mobile, side panel on desktop */}
                  <div className="order-1 lg:order-2 lg:col-span-1">
                    <div className="flex flex-col gap-4 md:gap-6">
                      {/* Orb with growth visualization - compact on mobile */}
                      <div 
                        className="bg-slate-900/50 backdrop-blur-xl rounded-2xl md:rounded-3xl border border-cyan-500/20 p-3 md:p-4"
                        ref={(el) => {
                          if (el) {
                            // Set both refs for data flow animation
                            animationRef.setOrbRef(el);
                          }
                        }}
                      >
                        <MaxOrb 
                          ref={orbRef}
                          isThinking={isTyping} 
                          growthLevel={orbGrowthLevel}
                          ingestPulse={orbIngestPulse}
                          releasePulse={orbReleasePulse}
                        />
                      </div>

                      {/* What I've learned panel - collapsible summary on mobile */}
                      <div 
                        className="hidden md:block"
                        ref={(el) => {
                          if (el) {
                            (notesPanelRef as any).current = el;
                            animationRef.setNotesRef(el);
                          }
                        }}
                      >
                        <LearnedInfoPanel 
                          learnedInfo={learnedInfo} 
                          newItemIds={newLearnedIds}
                        />
                      </div>

                      {/* Mobile: compact learned info indicator */}
                      <div className="md:hidden bg-slate-900/60 backdrop-blur-xl rounded-2xl border border-cyan-500/30 p-3">
                        <div className="flex items-center justify-between mb-2">
                          <div className="flex items-center gap-2">
                            <Brain className="w-4 h-4 text-cyan-400" />
                            <span className="text-white text-sm font-medium">
                              {learnedInfo.length === 0 ? 'Learning...' : `${learnedInfo.length} insights`}
                            </span>
                          </div>
                          {learnedInfo.length >= 3 && (
                            <button
                              onClick={() => setCurrentStep('learning')}
                              className="text-xs bg-cyan-500/20 text-cyan-400 px-3 py-1.5 rounded-full"
                            >
                              View All
                            </button>
                          )}
                        </div>
                        {/* Fix #3 & #6: Manual exit on mobile - more prominent */}
                        <button
                          onClick={() => window.location.hash = '#/team'}
                          className="w-full text-sm text-orange-400 hover:text-orange-300 py-2 mt-2 border border-orange-500/30 rounded-lg bg-orange-600/10 transition-colors font-medium"
                        >
                          <LogOut className="w-3 h-3 inline-block mr-1" /> Skip → Set up org manually
                        </button>
                      </div>

                      {/* Context scores - hidden on mobile */}
                      <div className="hidden md:block">
                        {contextScores.length > 0 && (
                          <ContextScores scores={contextScores} />
                        )}
                      </div>
                      
                      {/* Action button when enough learning - desktop only */}
                      {learnedInfo.length >= 5 && (
                        <motion.button
                          initial={{ opacity: 0, y: 10 }}
                          animate={{ opacity: 1, y: 0 }}
                          onClick={() => setCurrentStep('learning')}
                          className="hidden md:flex w-full bg-gradient-to-r from-cyan-500/20 to-blue-500/20 border border-cyan-500/30 text-cyan-400 font-semibold px-6 py-4 rounded-2xl hover:bg-cyan-500/30 transition-all items-center justify-center gap-2"
                        >
                          <Lightbulb className="w-5 h-5" />
                          See What I've Learned
                        </motion.button>
                      )}
                      
                      {/* Fix #3 & #6: Manual exit button - always visible, prominent styling */}
                      <motion.button
                        initial={{ opacity: 1 }}
                        animate={{ opacity: 1 }}
                        onClick={() => window.location.hash = '#/team'}
                        className="hidden md:flex w-full bg-orange-600/20 border-2 border-orange-500/50 text-orange-300 font-semibold px-4 py-3 rounded-xl hover:bg-orange-500/30 hover:text-orange-200 hover:border-orange-400 transition-all items-center justify-center gap-2 text-sm"
                      >
                        <LogOut className="w-4 h-4" />
                        Skip to Org Chart — Set up manually
                      </motion.button>
                    </div>
                  </div>
                  
                  {/* Chat interface - primary content */}
                  <div 
                    className="order-2 lg:order-1 lg:col-span-2"
                    ref={(el) => {
                      if (el) {
                        (chatContainerRef as any).current = el;
                        animationRef.setChatRef(el);
                      }
                    }}
                  >
                    <ChatInterface
                      messages={messages}
                      onMessage={handleMessage}
                      isTyping={isTyping}
                      voiceEnabled={true}
                      onVoiceToggle={setVoiceEnabled}
                      className="h-[400px] md:h-[600px]"
                      demoLimitReached={demoLimitReached}
                      onSignupClick={() => {
                        // Navigate to Max demo page on staging
                        window.open('https://eborro.com/orion/ienable-staging/admin/#/max', '_blank');
                      }}
                    />
                  </div>
                </div>
              </div>
            </div>
          );
        }}
      </DataFlowAnimation>
    );
  }

  // Learning/Mind map view
  if (currentStep === 'learning') {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-900 p-3 md:p-8 overflow-x-hidden">
        <div className="max-w-7xl mx-auto w-full">
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-6 md:mb-8 text-center"
          >
            <h1 className="text-3xl md:text-5xl font-bold text-white mb-2 md:mb-4">
              Knowledge <span className="bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent">Acquired</span>
            </h1>
            <p className="text-white/60 text-sm md:text-lg">
              Here's what I've learned about your organization
            </p>
          </motion.div>

          {/* Mobile-first layout */}
          <div className="flex flex-col lg:grid lg:grid-cols-3 gap-4 md:gap-6 mb-6 md:mb-8">
            {/* Learned info panel - shown first on mobile */}
            <div className="order-1 lg:order-2 space-y-4 md:space-y-6">
              <LearnedInfoPanel learnedInfo={learnedInfo} newItemIds={newLearnedIds} />
              <div className="hidden lg:block">
                <ContextScores scores={contextScores} />
              </div>
            </div>
            
            {/* Mind map - main content */}
            <div className="order-2 lg:order-1 lg:col-span-2">
              <MindMap nodes={mindMapNodes} />
            </div>
          </div>

          <div className="flex flex-col sm:flex-row gap-3 md:gap-4 justify-center">
            <motion.button
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.3 }}
              onClick={() => setCurrentStep('chat')}
              className="bg-slate-800/50 border border-white/10 text-white font-semibold px-6 md:px-8 py-3 md:py-4 rounded-2xl hover:bg-slate-700/50 transition-all inline-flex items-center justify-center gap-2 text-sm md:text-base"
            >
              Continue Conversation
            </motion.button>
            
            <motion.button
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.5 }}
              onClick={() => setCurrentStep('summary')}
              className="bg-gradient-to-r from-cyan-500 to-blue-500 text-white font-semibold px-8 md:px-12 py-3 md:py-4 rounded-2xl hover:shadow-2xl hover:shadow-cyan-500/30 transition-all active:scale-95 inline-flex items-center justify-center gap-2 md:gap-3 text-sm md:text-base"
            >
              Complete Onboarding
              <ArrowRight className="w-4 h-4 md:w-5 md:h-5" />
            </motion.button>
          </div>
        </div>
      </div>
    );
  }

  // Summary screen
  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-900 flex items-center justify-center p-4 overflow-x-hidden">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="max-w-2xl w-full text-center px-2"
      >
        <motion.div
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ type: 'spring', stiffness: 200, damping: 20 }}
          className="mb-6 md:mb-8"
        >
          <CheckCircle className="w-24 h-24 md:w-32 md:h-32 text-green-400 mx-auto" />
        </motion.div>

        <h1 className="text-4xl md:text-6xl font-bold text-white mb-4 md:mb-6">
          Onboarding <span className="bg-gradient-to-r from-cyan-400 to-green-400 bg-clip-text text-transparent">Complete</span>
        </h1>
        
        <p className="text-lg md:text-xl text-white/80 mb-3 md:mb-4">
          I'm now your AI Executive Partner
        </p>
        
        <p className="text-white/60 mb-6 md:mb-8 max-w-lg mx-auto text-sm md:text-base">
          I've learned {learnedInfo.length} key insights about your organization. 
          I'm ready to help you optimize operations and achieve your goals.
        </p>

        {/* Summary of what was learned */}
        {learnedInfo.length > 0 && (
          <div className="bg-slate-900/50 backdrop-blur-xl rounded-2xl md:rounded-3xl border border-cyan-500/20 p-4 md:p-6 mb-6 md:mb-8 text-left">
            <h3 className="text-white font-semibold mb-3 md:mb-4 flex items-center gap-2 text-sm md:text-base">
              <Brain className="w-4 h-4 md:w-5 md:h-5 text-cyan-400" />
              Key Insights
            </h3>
            <ul className="space-y-2">
              {learnedInfo.slice(0, 5).map((item, index) => (
                <motion.li
                  key={item.id}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: index * 0.1 }}
                  className="flex items-start gap-2 md:gap-3"
                >
                  <CheckCircle className="w-4 h-4 md:w-5 md:h-5 text-cyan-400 flex-shrink-0 mt-0.5" />
                  <span className="text-white/80 text-sm md:text-base">{item.text}</span>
                </motion.li>
              ))}
              {learnedInfo.length > 5 && (
                <li className="text-white/50 text-xs md:text-sm pl-6 md:pl-8">
                  ...and {learnedInfo.length - 5} more insights
                </li>
              )}
            </ul>
          </div>
        )}

        <button
          onClick={() => window.location.hash = '#/dashboard'}
          className="bg-gradient-to-r from-cyan-500 to-blue-500 text-white font-semibold px-8 md:px-12 py-4 md:py-5 rounded-2xl hover:shadow-2xl hover:shadow-cyan-500/30 transition-all active:scale-95 inline-flex items-center gap-2 md:gap-3 text-base md:text-lg"
        >
          Go to Dashboard
          <ArrowRight className="w-5 h-5 md:w-6 md:h-6" />
        </button>
      </motion.div>
    </div>
  );
}
