import { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

// ============================================
// ENABLE TEXT COMPONENT
// Emphasizes "ENABLE" with branded color and animated effects
// Easter egg tooltip explaining ienable's definition
// ============================================

interface EnableTextProps {
  children?: string;
  className?: string;
  size?: 'sm' | 'md' | 'lg' | 'xl';
  showTooltip?: boolean;
}

const sizeClasses = {
  sm: 'text-sm',
  md: 'text-base',
  lg: 'text-lg',
  xl: 'text-xl',
};

export function EnableText({ 
  children = 'ENABLE', 
  className = '',
  size = 'md',
  showTooltip = true,
}: EnableTextProps) {
  const [isHovered, setIsHovered] = useState(false);
  const [showEasterEgg, setShowEasterEgg] = useState(false);
  const hoverTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const handleMouseEnter = () => {
    setIsHovered(true);
    // Show easter egg tooltip after hovering for 1.5 seconds
    if (showTooltip) {
      hoverTimeoutRef.current = setTimeout(() => {
        setShowEasterEgg(true);
      }, 1500);
    }
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
    setShowEasterEgg(false);
    if (hoverTimeoutRef.current) {
      clearTimeout(hoverTimeoutRef.current);
    }
  };

  return (
    <span 
      className={`relative inline-block ${className}`}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <motion.span
        className={`
          relative font-bold cursor-help
          bg-gradient-to-r from-cyan-400 via-emerald-400 to-cyan-400
          bg-clip-text text-transparent
          bg-[length:200%_100%]
          ${sizeClasses[size]}
        `}
        animate={{
          backgroundPosition: isHovered ? ['0% 50%', '100% 50%', '0% 50%'] : '0% 50%',
        }}
        transition={{
          duration: 2,
          repeat: isHovered ? Infinity : 0,
          ease: 'linear',
        }}
        style={{
          textShadow: isHovered ? '0 0 20px rgba(6, 182, 212, 0.5)' : 'none',
        }}
      >
        {children}
        
        {/* Underline glow effect */}
        <motion.span
          className="absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r from-cyan-400 to-emerald-400"
          initial={{ scaleX: 0 }}
          animate={{ scaleX: isHovered ? 1 : 0 }}
          transition={{ duration: 0.3 }}
        />
      </motion.span>

      {/* Easter egg tooltip */}
      <AnimatePresence>
        {showEasterEgg && (
          <motion.div
            initial={{ opacity: 0, y: 10, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.9 }}
            transition={{ duration: 0.3 }}
            className="absolute z-50 left-1/2 -translate-x-1/2 bottom-full mb-3 w-80 max-w-[90vw] pointer-events-none"
          >
            <div className="bg-slate-900/95 backdrop-blur-xl rounded-xl border border-cyan-500/40 p-5 shadow-xl shadow-cyan-500/20">
              <div className="text-cyan-400 font-semibold text-sm mb-3 flex items-center gap-2">
                <span className="text-lg">🚀</span>
                What does "ENABLE" mean?
              </div>
              <div className="text-white/90 text-sm leading-relaxed space-y-3">
                <p>
                  <strong className="text-emerald-400">E</strong>mpowering{' '}
                  <strong className="text-emerald-400">N</strong>ew{' '}
                  <strong className="text-emerald-400">A</strong>I-driven{' '}
                  <strong className="text-emerald-400">B</strong>usiness{' '}
                  <strong className="text-emerald-400">L</strong>everage for{' '}
                  <strong className="text-emerald-400">E</strong>veryone
                </p>
                <p className="text-white/60 italic">
                  We don't replace humans — we give them superpowers.
                </p>
              </div>
              {/* Arrow */}
              <div className="absolute left-1/2 -translate-x-1/2 -bottom-2 w-4 h-4 bg-slate-900/95 border-r border-b border-cyan-500/40 transform rotate-45" />
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </span>
  );
}

// Higher emphasis version for headers
export function EnableTextBig({ 
  children = 'ENABLE', 
  className = '',
}: { children?: string; className?: string }) {
  const [isHovered, setIsHovered] = useState(false);
  const [showTooltip, setShowTooltip] = useState(false);
  const hoverTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const handleMouseEnter = () => {
    setIsHovered(true);
    hoverTimeoutRef.current = setTimeout(() => {
      setShowTooltip(true);
    }, 1200);
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
    setShowTooltip(false);
    if (hoverTimeoutRef.current) {
      clearTimeout(hoverTimeoutRef.current);
    }
  };

  return (
    <span 
      className={`relative inline-block ${className}`}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <motion.span
        className="relative font-black cursor-help"
        animate={{
          textShadow: isHovered 
            ? [
                '0 0 10px rgba(6, 182, 212, 0.8), 0 0 20px rgba(6, 182, 212, 0.5), 0 0 30px rgba(16, 185, 129, 0.3)',
                '0 0 20px rgba(6, 182, 212, 0.9), 0 0 40px rgba(6, 182, 212, 0.6), 0 0 60px rgba(16, 185, 129, 0.4)',
                '0 0 10px rgba(6, 182, 212, 0.8), 0 0 20px rgba(6, 182, 212, 0.5), 0 0 30px rgba(16, 185, 129, 0.3)',
              ]
            : '0 0 5px rgba(6, 182, 212, 0.3)',
        }}
        transition={{
          duration: 1.5,
          repeat: isHovered ? Infinity : 0,
          ease: 'easeInOut',
        }}
        style={{
          background: 'linear-gradient(135deg, #06B6D4 0%, #10B981 50%, #06B6D4 100%)',
          backgroundSize: '200% 200%',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          backgroundClip: 'text',
          animation: isHovered ? 'shimmer 2s linear infinite' : 'none',
        }}
      >
        {children}
      </motion.span>

      {/* Spark particles on hover */}
      <AnimatePresence>
        {isHovered && (
          <>
            {[...Array(6)].map((_, i) => (
              <motion.span
                key={i}
                className="absolute w-1 h-1 bg-cyan-400 rounded-full pointer-events-none"
                initial={{ 
                  opacity: 0,
                  x: '50%',
                  y: '50%',
                }}
                animate={{
                  opacity: [0, 1, 0],
                  x: `${50 + (Math.random() - 0.5) * 100}%`,
                  y: `${50 + (Math.random() - 0.5) * 100}%`,
                  scale: [0, 1.5, 0],
                }}
                transition={{
                  duration: 0.8 + Math.random() * 0.5,
                  delay: i * 0.1,
                  repeat: Infinity,
                  repeatDelay: 0.5,
                }}
              />
            ))}
          </>
        )}
      </AnimatePresence>

      {/* Easter egg tooltip */}
      <AnimatePresence>
        {showTooltip && (
          <motion.div
            initial={{ opacity: 0, y: 10, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.9 }}
            transition={{ duration: 0.3 }}
            className="absolute z-50 left-1/2 -translate-x-1/2 bottom-full mb-4 w-96 max-w-[90vw] pointer-events-none"
          >
            <div className="bg-gradient-to-br from-slate-900 to-slate-800 backdrop-blur-xl rounded-2xl border border-cyan-500/50 p-6 shadow-2xl shadow-cyan-500/30">
              <div className="text-center mb-3">
                <span className="text-3xl">✨</span>
              </div>
              <div className="text-cyan-400 font-bold text-center text-lg mb-4">
                The ienable Philosophy
              </div>
              <div className="text-white/90 text-base text-center leading-relaxed space-y-4">
                <p>
                  <span className="text-emerald-400 font-bold">E</span>mpowering{' '}
                  <span className="text-emerald-400 font-bold">N</span>ew{' '}
                  <span className="text-emerald-400 font-bold">A</span>I-driven{' '}
                  <span className="text-emerald-400 font-bold">B</span>usiness{' '}
                  <span className="text-emerald-400 font-bold">L</span>everage for{' '}
                  <span className="text-emerald-400 font-bold">E</span>veryone
                </p>
                <p className="text-cyan-300/80 text-xs italic pt-2 border-t border-cyan-500/20">
                  "We don't replace humans — we give them superpowers to grow."
                </p>
              </div>
              {/* Arrow */}
              <div className="absolute left-1/2 -translate-x-1/2 -bottom-2 w-4 h-4 bg-slate-800 border-r border-b border-cyan-500/50 transform rotate-45" />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        @keyframes shimmer {
          0% { background-position: 0% 50%; }
          50% { background-position: 100% 50%; }
          100% { background-position: 0% 50%; }
        }
      `}</style>
    </span>
  );
}

export default EnableText;
