import { motion } from 'framer-motion';
import { CheckCircle2, Circle } from 'lucide-react';

export interface ContextScore {
  id: string;
  label: string;
  category: 'department' | 'user' | 'company';
  score: number; // 0-100
  total?: number;
  current?: number;
}

interface ContextScoresProps {
  scores: ContextScore[];
  className?: string;
}

const categoryColors = {
  department: 'from-cyan-500 to-blue-500',
  user: 'from-purple-500 to-pink-500',
  company: 'from-green-500 to-emerald-500',
};

// Fix #8: Onboarding-specific labels
const categoryLabels = {
  department: 'Structure',
  user: 'Goals',
  company: 'Business Context',
};

export function ContextScores({ scores, className = '' }: ContextScoresProps) {
  // Group scores by category
  const groupedScores = scores.reduce((acc, score) => {
    if (!acc[score.category]) {
      acc[score.category] = [];
    }
    acc[score.category].push(score);
    return acc;
  }, {} as Record<string, ContextScore[]>);

  // Calculate overall progress
  const overallScore = scores.length > 0 
    ? Math.round(scores.reduce((sum, s) => sum + s.score, 0) / scores.length)
    : 0;

  // Fix #8: Estimate questions remaining (target ~10 questions total)
  const questionsAsked = Math.floor(overallScore / 10);
  const questionsRemaining = Math.max(0, 10 - questionsAsked);

  return (
    <div className={`bg-slate-900/50 backdrop-blur-xl rounded-3xl border border-cyan-500/20 p-6 ${className}`}>
      {/* Fix #8: De-emphasize lifetime stats, show onboarding-specific progress */}
      <div className="mb-6">
        <div className="flex items-center justify-between">
          <h3 className="text-white font-semibold text-lg">Context Acquisition</h3>
          <motion.span
            key={overallScore}
            initial={{ scale: 1.2, color: '#22D3EE' }}
            animate={{ scale: 1, color: overallScore > 0 ? '#94A3B8' : '#475569' }}
            className="text-sm font-medium"
          >
            {overallScore}%
          </motion.span>
        </div>
        {/* Updated messaging - feels completable */}
        <p className="text-white/60 text-sm mt-1">
          {overallScore === 0 
            ? 'Answer a few questions to get started' 
            : overallScore < 30 
            ? `~${questionsRemaining} questions to go`
            : overallScore < 60
            ? `Great progress! ~${questionsRemaining} more to understand you fully`
            : overallScore < 90
            ? 'Almost there! Just a couple more details...'
            : 'Ready to build your AI team! ✨'
          }
        </p>
      </div>

      <div className="space-y-6">
        {Object.entries(groupedScores).map(([category, categoryScores]) => (
          <div key={category}>
            {/* Category header */}
            <div className="flex items-center gap-2 mb-3">
              <div className={`w-2 h-2 rounded-full bg-gradient-to-r ${categoryColors[category as keyof typeof categoryColors]}`} />
              <h4 className="text-white/90 font-medium text-sm">
                {categoryLabels[category as keyof typeof categoryLabels]}
              </h4>
              <span className="text-white/40 text-xs ml-auto">
                {categoryScores.filter(s => s.score === 100).length} / {categoryScores.length}
              </span>
            </div>

            {/* Progress bars */}
            <div className="space-y-3">
              {categoryScores.map((score, index) => (
                <motion.div
                  key={score.id}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: index * 0.1 }}
                  className="space-y-2"
                >
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-white/80">{score.label}</span>
                    <div className="flex items-center gap-2">
                      {score.current !== undefined && score.total !== undefined && (
                        <span className="text-white/40 text-xs">
                          {score.current}/{score.total}
                        </span>
                      )}
                      <span className="text-white/60 font-medium">
                        {Math.round(score.score)}%
                      </span>
                      {score.score === 100 ? (
                        <CheckCircle2 className="w-4 h-4 text-green-400" />
                      ) : (
                        <Circle className="w-4 h-4 text-white/20" />
                      )}
                    </div>
                  </div>
                  
                  {/* Progress bar */}
                  <div className="relative h-2 bg-slate-800/50 rounded-full overflow-hidden">
                    <motion.div
                      initial={{ width: 0 }}
                      animate={{ width: `${score.score}%` }}
                      transition={{
                        duration: 1,
                        delay: index * 0.1,
                        ease: 'easeOut',
                      }}
                      className={`absolute inset-y-0 left-0 bg-gradient-to-r ${categoryColors[category as keyof typeof categoryColors]} rounded-full`}
                    >
                      {/* Shimmer effect */}
                      <motion.div
                        className="absolute inset-0 bg-gradient-to-r from-transparent via-white/30 to-transparent"
                        animate={{
                          x: ['-100%', '100%'],
                        }}
                        transition={{
                          duration: 2,
                          repeat: Infinity,
                          ease: 'linear',
                        }}
                        style={{ width: '50%' }}
                      />
                    </motion.div>
                  </div>
                </motion.div>
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* Overall progress */}
      <div className="mt-6 pt-6 border-t border-cyan-500/20">
        <div className="flex items-center justify-between mb-3">
          <span className="text-white font-medium">Overall Context</span>
          <motion.span 
            key={overallScore}
            initial={{ scale: 1.1 }}
            animate={{ scale: 1 }}
            className="text-white/60 font-medium"
          >
            {overallScore}%
          </motion.span>
        </div>
        <div className="relative h-3 bg-slate-800/50 rounded-full overflow-hidden">
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${overallScore}%` }}
            transition={{ duration: 0.8, ease: 'easeOut' }}
            className={`absolute inset-y-0 left-0 rounded-full ${
              overallScore === 0 
                ? 'bg-slate-600' 
                : 'bg-gradient-to-r from-cyan-500 via-blue-500 to-purple-500'
            }`}
          >
            {/* Animated shimmer - only show when there's progress */}
            {overallScore > 0 && (
              <motion.div
                className="absolute inset-0 bg-gradient-to-r from-transparent via-white/30 to-transparent"
                animate={{ x: ['-100%', '100%'] }}
                transition={{ duration: 2, repeat: Infinity, ease: 'linear' }}
                style={{ width: '50%' }}
              />
            )}
          </motion.div>
        </div>
      </div>
    </div>
  );
}
