import { useRef, useEffect, useState, forwardRef, useImperativeHandle, useCallback } from 'react';

// ============================================
// THE NEURAL ORB - Learning Brain Visualization
// ============================================
// "The orb starts as a little dot and turns into
// this complex galaxy with all kinds of things
// connected and processing. That is the electricity."
// 
// NOT: Random lightning
// YES: Purposeful connections between learned concepts

export interface MaxOrbRef {
  triggerIngest?: () => void;
  triggerRelease?: () => void;
  getElement?: () => HTMLDivElement | null;
  addConcept?: (name?: string) => void;
}

interface MaxOrbNeuralProps {
  isThinking?: boolean;
  growthLevel?: number; // 0-10 - controls how many nodes/connections exist
  intensity?: number; // 0-1 for activity level  
  ingestPulse?: boolean;
  releasePulse?: boolean;
  onHover?: (isHovered: boolean) => void;
  onClick?: () => void;
  showInteractionHint?: boolean;
}

// ============================================
// DATA STRUCTURES
// ============================================

interface NeuralNode {
  id: number;
  x: number;
  y: number;
  z: number; // For depth/parallax
  radius: number;
  baseRadius: number;
  pulsePhase: number;
  color: { h: number; s: number; l: number };
  connections: number[];
  energy: number; // Current energy level (0-1)
  birthTime: number;
  concept?: string;
}

interface DataPacket {
  id: number;
  fromNode: number;
  toNode: number;
  progress: number; // 0-1
  speed: number;
  color: { h: number; s: number; l: number };
}

// ============================================
// NEURAL NETWORK CLASS
// ============================================

class NeuralNetwork {
  nodes: NeuralNode[] = [];
  packets: DataPacket[] = [];
  private nextNodeId = 0;
  private nextPacketId = 0;
  private centerX: number;
  private centerY: number;
  private maxRadius: number;
  
  constructor(width: number, height: number) {
    this.centerX = width / 2;
    this.centerY = height / 2;
    this.maxRadius = Math.min(width, height) * 0.35;
  }
  
  resize(width: number, height: number) {
    const oldCenterX = this.centerX;
    const oldCenterY = this.centerY;
    const oldMaxRadius = this.maxRadius;
    
    this.centerX = width / 2;
    this.centerY = height / 2;
    this.maxRadius = Math.min(width, height) * 0.35;
    
    // Rescale existing nodes
    const scaleX = this.centerX / oldCenterX;
    const scaleY = this.centerY / oldCenterY;
    const scaleR = this.maxRadius / oldMaxRadius;
    
    this.nodes.forEach(node => {
      node.x = (node.x - oldCenterX) * scaleR + this.centerX;
      node.y = (node.y - oldCenterY) * scaleR + this.centerY;
      node.radius *= scaleR;
      node.baseRadius *= scaleR;
    });
  }
  
  // Create the initial tiny dot (core)
  createCore(time: number) {
    if (this.nodes.length === 0) {
      this.nodes.push({
        id: this.nextNodeId++,
        x: this.centerX,
        y: this.centerY,
        z: 0,
        radius: 4,
        baseRadius: 4,
        pulsePhase: 0,
        color: { h: 185, s: 80, l: 55 }, // Cyan
        connections: [],
        energy: 1,
        birthTime: time,
        concept: 'core',
      });
    }
  }
  
  // Add a new learned concept (node)
  addNode(time: number, concept?: string): NeuralNode | null {
    if (this.nodes.length === 0) {
      this.createCore(time);
      return this.nodes[0];
    }
    
    // Find position near existing nodes but not overlapping
    const angle = Math.random() * Math.PI * 2;
    const distance = Math.min(
      this.maxRadius * 0.15 + Math.random() * this.maxRadius * 0.7,
      this.maxRadius * 0.95
    );
    
    // Position relative to a random existing node (clustering)
    const parentNode = this.nodes[Math.floor(Math.random() * this.nodes.length)];
    const spreadAngle = (Math.random() - 0.5) * Math.PI;
    
    let x = parentNode.x + Math.cos(angle + spreadAngle) * distance * 0.4;
    let y = parentNode.y + Math.sin(angle + spreadAngle) * distance * 0.4;
    
    // Keep within bounds
    const distFromCenter = Math.sqrt(
      Math.pow(x - this.centerX, 2) + Math.pow(y - this.centerY, 2)
    );
    if (distFromCenter > this.maxRadius) {
      const scale = this.maxRadius / distFromCenter;
      x = this.centerX + (x - this.centerX) * scale;
      y = this.centerY + (y - this.centerY) * scale;
    }
    
    const z = (Math.random() - 0.5) * 0.5; // Depth layer
    
    // Determine color based on depth and position
    const hue = 185 + Math.random() * 90; // Cyan to purple range
    
    const newNode: NeuralNode = {
      id: this.nextNodeId++,
      x,
      y,
      z,
      radius: 2 + Math.random() * 3,
      baseRadius: 2 + Math.random() * 3,
      pulsePhase: Math.random() * Math.PI * 2,
      color: { h: hue, s: 70 + Math.random() * 20, l: 50 + Math.random() * 15 },
      connections: [],
      energy: 0.5,
      birthTime: time,
      concept,
    };
    
    // Connect to nearby nodes (neural pathway formation)
    const connectionCount = Math.floor(1 + Math.random() * 3);
    const sortedByDistance = [...this.nodes]
      .map(n => ({
        node: n,
        dist: Math.sqrt(Math.pow(n.x - x, 2) + Math.pow(n.y - y, 2)),
      }))
      .sort((a, b) => a.dist - b.dist)
      .slice(0, connectionCount + 2);
    
    sortedByDistance.forEach((item, i) => {
      if (i < connectionCount && Math.random() > 0.2) {
        newNode.connections.push(item.node.id);
        item.node.connections.push(newNode.id);
      }
    });
    
    this.nodes.push(newNode);
    
    // Trigger energy pulse from connected nodes
    newNode.connections.forEach(connId => {
      const connNode = this.nodes.find(n => n.id === connId);
      if (connNode) {
        connNode.energy = 1;
        this.createPacket(connNode.id, newNode.id, time);
      }
    });
    
    return newNode;
  }
  
  // Create a data packet traveling along a connection
  createPacket(fromId: number, toId: number, time: number) {
    const fromNode = this.nodes.find(n => n.id === fromId);
    const toNode = this.nodes.find(n => n.id === toId);
    if (!fromNode || !toNode) return;
    
    this.packets.push({
      id: this.nextPacketId++,
      fromNode: fromId,
      toNode: toId,
      progress: 0,
      speed: 0.8 + Math.random() * 0.8,
      color: { 
        h: (fromNode.color.h + toNode.color.h) / 2, 
        s: 90, 
        l: 65 
      },
    });
  }
  
  // Random activity - data flowing through network
  triggerRandomActivity(intensity: number, time: number) {
    if (this.nodes.length < 2) return;
    
    // More activity with higher intensity
    const activityChance = 0.02 + intensity * 0.08;
    
    if (Math.random() < activityChance) {
      // Pick a random node with connections
      const nodesWithConnections = this.nodes.filter(n => n.connections.length > 0);
      if (nodesWithConnections.length === 0) return;
      
      const sourceNode = nodesWithConnections[
        Math.floor(Math.random() * nodesWithConnections.length)
      ];
      const targetId = sourceNode.connections[
        Math.floor(Math.random() * sourceNode.connections.length)
      ];
      
      this.createPacket(sourceNode.id, targetId, time);
      sourceNode.energy = Math.min(1, sourceNode.energy + 0.3);
    }
  }
  
  // Update all animations
  update(time: number, deltaTime: number, intensity: number) {
    // Update nodes
    this.nodes.forEach(node => {
      // Pulse animation
      node.pulsePhase += deltaTime * (1 + intensity);
      const pulse = Math.sin(node.pulsePhase) * 0.3;
      node.radius = node.baseRadius * (1 + pulse * (0.5 + node.energy * 0.5));
      
      // Energy decay
      node.energy = Math.max(0.1, node.energy - deltaTime * 0.5);
    });
    
    // Update packets
    this.packets.forEach(packet => {
      packet.progress += deltaTime * packet.speed;
      
      // When packet reaches destination
      if (packet.progress >= 1) {
        const targetNode = this.nodes.find(n => n.id === packet.toNode);
        if (targetNode) {
          targetNode.energy = Math.min(1, targetNode.energy + 0.4);
          
          // Chain reaction - small chance to continue
          if (Math.random() < 0.3 + intensity * 0.3 && targetNode.connections.length > 0) {
            const nextTarget = targetNode.connections.filter(c => c !== packet.fromNode);
            if (nextTarget.length > 0) {
              const next = nextTarget[Math.floor(Math.random() * nextTarget.length)];
              this.createPacket(targetNode.id, next, time);
            }
          }
        }
      }
    });
    
    // Remove completed packets
    this.packets = this.packets.filter(p => p.progress < 1);
    
    // Trigger random activity
    this.triggerRandomActivity(intensity, time);
  }
  
  // Set network to a specific growth level (0-10)
  setGrowthLevel(level: number, time: number) {
    const targetNodes = Math.floor(1 + level * level * 1.5); // Exponential growth
    
    // Add nodes if needed
    while (this.nodes.length < targetNodes) {
      this.addNode(time);
    }
  }
}

// ============================================
// RENDERER
// ============================================

function renderNetwork(
  ctx: CanvasRenderingContext2D,
  network: NeuralNetwork,
  time: number,
  intensity: number,
  width: number,
  height: number,
  isThinking: boolean,
) {
  ctx.clearRect(0, 0, width, height);
  
  const centerX = width / 2;
  const centerY = height / 2;
  const maxRadius = Math.min(width, height) * 0.35;
  
  // ========== BACKGROUND GLOW ==========
  const glowRadius = maxRadius * (1.2 + intensity * 0.3);
  const bgGlow = ctx.createRadialGradient(
    centerX, centerY, 0,
    centerX, centerY, glowRadius
  );
  bgGlow.addColorStop(0, `hsla(195, 80%, 50%, ${0.08 + intensity * 0.07})`);
  bgGlow.addColorStop(0.5, `hsla(260, 70%, 40%, ${0.04 + intensity * 0.03})`);
  bgGlow.addColorStop(1, 'transparent');
  ctx.fillStyle = bgGlow;
  ctx.fillRect(0, 0, width, height);
  
  // Sort nodes by z for depth rendering
  const sortedNodes = [...network.nodes].sort((a, b) => a.z - b.z);
  
  // ========== CONNECTIONS (behind nodes) ==========
  ctx.lineCap = 'round';
  
  network.nodes.forEach(node => {
    node.connections.forEach(connId => {
      if (connId < node.id) return; // Draw each connection once
      
      const connNode = network.nodes.find(n => n.id === connId);
      if (!connNode) return;
      
      // Connection glow based on both nodes' energy
      const energy = (node.energy + connNode.energy) / 2;
      const alpha = 0.1 + energy * 0.4;
      
      // Gradient along connection
      const gradient = ctx.createLinearGradient(node.x, node.y, connNode.x, connNode.y);
      gradient.addColorStop(0, `hsla(${node.color.h}, ${node.color.s}%, ${node.color.l}%, ${alpha})`);
      gradient.addColorStop(0.5, `hsla(${(node.color.h + connNode.color.h) / 2}, 80%, 60%, ${alpha * 1.2})`);
      gradient.addColorStop(1, `hsla(${connNode.color.h}, ${connNode.color.s}%, ${connNode.color.l}%, ${alpha})`);
      
      ctx.strokeStyle = gradient;
      ctx.lineWidth = 1 + energy * 2;
      
      ctx.beginPath();
      ctx.moveTo(node.x, node.y);
      
      // Slight curve for organic feel
      const midX = (node.x + connNode.x) / 2 + (Math.sin(time + node.id) * 5);
      const midY = (node.y + connNode.y) / 2 + (Math.cos(time + connNode.id) * 5);
      ctx.quadraticCurveTo(midX, midY, connNode.x, connNode.y);
      ctx.stroke();
    });
  });
  
  // ========== DATA PACKETS (the "electricity") ==========
  network.packets.forEach(packet => {
    const fromNode = network.nodes.find(n => n.id === packet.fromNode);
    const toNode = network.nodes.find(n => n.id === packet.toNode);
    if (!fromNode || !toNode) return;
    
    const t = packet.progress;
    
    // Curved path (same as connection)
    const midX = (fromNode.x + toNode.x) / 2 + (Math.sin(time + fromNode.id) * 5);
    const midY = (fromNode.y + toNode.y) / 2 + (Math.cos(time + toNode.id) * 5);
    
    // Quadratic bezier position
    const x = Math.pow(1 - t, 2) * fromNode.x + 2 * (1 - t) * t * midX + Math.pow(t, 2) * toNode.x;
    const y = Math.pow(1 - t, 2) * fromNode.y + 2 * (1 - t) * t * midY + Math.pow(t, 2) * toNode.y;
    
    // Glowing packet
    const packetSize = 4 + Math.sin(t * Math.PI) * 3;
    
    // Outer glow
    const glowGradient = ctx.createRadialGradient(x, y, 0, x, y, packetSize * 3);
    glowGradient.addColorStop(0, `hsla(${packet.color.h}, ${packet.color.s}%, ${packet.color.l}%, 0.8)`);
    glowGradient.addColorStop(0.5, `hsla(${packet.color.h}, ${packet.color.s}%, ${packet.color.l}%, 0.3)`);
    glowGradient.addColorStop(1, 'transparent');
    
    ctx.fillStyle = glowGradient;
    ctx.beginPath();
    ctx.arc(x, y, packetSize * 3, 0, Math.PI * 2);
    ctx.fill();
    
    // Core
    ctx.fillStyle = `hsla(${packet.color.h}, 90%, 75%, 1)`;
    ctx.beginPath();
    ctx.arc(x, y, packetSize, 0, Math.PI * 2);
    ctx.fill();
    
    // Bright center
    ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
    ctx.beginPath();
    ctx.arc(x, y, packetSize * 0.4, 0, Math.PI * 2);
    ctx.fill();
    
    // Trail
    const trailLength = 5;
    for (let i = 1; i <= trailLength; i++) {
      const trailT = Math.max(0, t - i * 0.03);
      const trailX = Math.pow(1 - trailT, 2) * fromNode.x + 2 * (1 - trailT) * trailT * midX + Math.pow(trailT, 2) * toNode.x;
      const trailY = Math.pow(1 - trailT, 2) * fromNode.y + 2 * (1 - trailT) * trailT * midY + Math.pow(trailT, 2) * toNode.y;
      const trailAlpha = 0.4 * (1 - i / trailLength);
      const trailSize = packetSize * (1 - i / trailLength * 0.5);
      
      ctx.fillStyle = `hsla(${packet.color.h}, ${packet.color.s}%, ${packet.color.l}%, ${trailAlpha})`;
      ctx.beginPath();
      ctx.arc(trailX, trailY, trailSize, 0, Math.PI * 2);
      ctx.fill();
    }
  });
  
  // ========== NODES ==========
  sortedNodes.forEach(node => {
    // Skip rendering the core node - we have an HTML overlay dot that follows the mouse
    if (node.concept === 'core') return;
    
    const depthScale = 1 + node.z * 0.2;
    const depthAlpha = 0.7 + (1 - Math.abs(node.z)) * 0.3;
    const r = node.radius * depthScale;
    
    // Multi-layer glow
    const glowLayers = [
      { size: 6, alpha: 0.05 + node.energy * 0.1 },
      { size: 4, alpha: 0.1 + node.energy * 0.15 },
      { size: 2.5, alpha: 0.15 + node.energy * 0.2 },
      { size: 1.5, alpha: 0.3 + node.energy * 0.3 },
    ];
    
    glowLayers.forEach(layer => {
      const gradient = ctx.createRadialGradient(
        node.x, node.y, 0,
        node.x, node.y, r * layer.size
      );
      gradient.addColorStop(0, `hsla(${node.color.h}, ${node.color.s}%, ${node.color.l}%, ${layer.alpha * depthAlpha})`);
      gradient.addColorStop(1, 'transparent');
      
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(node.x, node.y, r * layer.size, 0, Math.PI * 2);
      ctx.fill();
    });
    
    // Core
    ctx.fillStyle = `hsla(${node.color.h}, ${node.color.s}%, ${node.color.l + 10}%, ${depthAlpha})`;
    ctx.beginPath();
    ctx.arc(node.x, node.y, r, 0, Math.PI * 2);
    ctx.fill();
    
    // Bright center
    const centerBrightness = 70 + node.energy * 25;
    ctx.fillStyle = `hsla(${node.color.h}, 70%, ${centerBrightness}%, ${depthAlpha})`;
    ctx.beginPath();
    ctx.arc(node.x, node.y, r * 0.5, 0, Math.PI * 2);
    ctx.fill();
    
    // White hot center when energized
    if (node.energy > 0.5) {
      ctx.fillStyle = `rgba(255, 255, 255, ${(node.energy - 0.5) * depthAlpha})`;
      ctx.beginPath();
      ctx.arc(node.x, node.y, r * 0.25, 0, Math.PI * 2);
      ctx.fill();
    }
  });
  
  // ========== THINKING PULSE ==========
  if (isThinking) {
    const pulsePhase = (time * 3) % (Math.PI * 2);
    const pulseRadius = maxRadius * (0.3 + Math.sin(pulsePhase) * 0.7);
    const pulseAlpha = Math.max(0, 0.15 * (1 - Math.sin(pulsePhase)));
    
    const pulseGradient = ctx.createRadialGradient(
      centerX, centerY, pulseRadius * 0.9,
      centerX, centerY, pulseRadius
    );
    pulseGradient.addColorStop(0, 'transparent');
    pulseGradient.addColorStop(0.5, `hsla(195, 80%, 60%, ${pulseAlpha})`);
    pulseGradient.addColorStop(1, 'transparent');
    
    ctx.strokeStyle = pulseGradient;
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(centerX, centerY, pulseRadius, 0, Math.PI * 2);
    ctx.stroke();
  }
  
  // ========== OUTER RING ==========
  const ringAlpha = 0.1 + intensity * 0.15;
  ctx.strokeStyle = `hsla(195, 70%, 50%, ${ringAlpha})`;
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.arc(centerX, centerY, maxRadius, 0, Math.PI * 2);
  ctx.stroke();
  
  // Second ring
  ctx.strokeStyle = `hsla(260, 60%, 50%, ${ringAlpha * 0.5})`;
  ctx.beginPath();
  ctx.arc(centerX, centerY, maxRadius * 1.05, 0, Math.PI * 2);
  ctx.stroke();
}

// ============================================
// MAIN COMPONENT
// ============================================

export const MaxOrbNeural = forwardRef<MaxOrbRef, MaxOrbNeuralProps>(({
  isThinking = false,
  growthLevel = 0,
  intensity = 0.5,
  ingestPulse = false,
  releasePulse = false,
  onHover,
  onClick,
  showInteractionHint = false,
}, ref) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const networkRef = useRef<NeuralNetwork | null>(null);
  const animationRef = useRef<number>(0);
  const lastTimeRef = useRef<number>(0);
  const lastGrowthRef = useRef<number>(0);
  
  const [ingestFlash, setIngestFlash] = useState(false);
  const [releaseFlash, setReleaseFlash] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  
  // Mouse tracking for the inner dot
  const [mousePos, setMousePos] = useState({ x: 0.5, y: 0.5 }); // Normalized 0-1
  const [dotPos, setDotPos] = useState({ x: 0.5, y: 0.5 }); // Smoothed position
  const idlePhaseRef = useRef(0);
  
  // Mouse tracking handler
  const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return;
    
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top) / rect.height;
    setMousePos({ x: Math.max(0, Math.min(1, x)), y: Math.max(0, Math.min(1, y)) });
  }, []);
  
  // Smooth dot movement towards mouse (or idle animation)
  useEffect(() => {
    let frameId: number;
    
    const updateDot = () => {
      setDotPos(prev => {
        if (isHovered) {
          // Follow mouse with easing
          const easing = 0.08;
          return {
            x: prev.x + (mousePos.x - prev.x) * easing,
            y: prev.y + (mousePos.y - prev.y) * easing,
          };
        } else {
          // Idle animation - gentle floating motion
          idlePhaseRef.current += 0.015;
          const centerX = 0.5 + Math.sin(idlePhaseRef.current) * 0.08;
          const centerY = 0.5 + Math.cos(idlePhaseRef.current * 0.7) * 0.06;
          const easing = 0.05;
          return {
            x: prev.x + (centerX - prev.x) * easing,
            y: prev.y + (centerY - prev.y) * easing,
          };
        }
      });
      frameId = requestAnimationFrame(updateDot);
    };
    
    frameId = requestAnimationFrame(updateDot);
    return () => cancelAnimationFrame(frameId);
  }, [isHovered, mousePos]);
  
  // Hover handlers
  const handleMouseEnter = useCallback(() => {
    setIsHovered(true);
    onHover?.(true);
  }, [onHover]);
  
  const handleMouseLeave = useCallback(() => {
    setIsHovered(false);
    onHover?.(false);
  }, [onHover]);
  
  const handleClick = useCallback(() => {
    onClick?.();
  }, [onClick]);
  
  // Expose methods via ref
  useImperativeHandle(ref, () => ({
    triggerIngest: () => {
      setIngestFlash(true);
      setTimeout(() => setIngestFlash(false), 600);
      // Add a new concept node when ingesting
      if (networkRef.current) {
        networkRef.current.addNode(performance.now() / 1000);
      }
    },
    triggerRelease: () => {
      setReleaseFlash(true);
      setTimeout(() => setReleaseFlash(false), 600);
      // Trigger cascade activity
      if (networkRef.current) {
        for (let i = 0; i < 5; i++) {
          setTimeout(() => {
            networkRef.current?.triggerRandomActivity(1, performance.now() / 1000);
          }, i * 100);
        }
      }
    },
    getElement: () => containerRef.current,
    addConcept: (name?: string) => {
      if (networkRef.current) {
        networkRef.current.addNode(performance.now() / 1000, name);
      }
    },
  }), []);
  
  // React to prop-based pulses
  useEffect(() => {
    if (ingestPulse) {
      setIngestFlash(true);
      setTimeout(() => setIngestFlash(false), 600);
      if (networkRef.current) {
        networkRef.current.addNode(performance.now() / 1000);
      }
    }
  }, [ingestPulse]);
  
  useEffect(() => {
    if (releasePulse) {
      setReleaseFlash(true);
      setTimeout(() => setReleaseFlash(false), 600);
      if (networkRef.current) {
        for (let i = 0; i < 5; i++) {
          setTimeout(() => {
            networkRef.current?.triggerRandomActivity(1, performance.now() / 1000);
          }, i * 100);
        }
      }
    }
  }, [releasePulse]);
  
  // Initialize network and animation loop
  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;
    
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    
    // Set up canvas size
    const updateSize = () => {
      const rect = container.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      canvas.style.width = `${rect.width}px`;
      canvas.style.height = `${rect.height}px`;
      ctx.scale(dpr, dpr);
      
      if (networkRef.current) {
        networkRef.current.resize(rect.width, rect.height);
      } else {
        networkRef.current = new NeuralNetwork(rect.width, rect.height);
        networkRef.current.createCore(performance.now() / 1000);
      }
    };
    
    updateSize();
    window.addEventListener('resize', updateSize);
    
    // Animation loop
    const animate = (timestamp: number) => {
      const time = timestamp / 1000;
      const deltaTime = lastTimeRef.current ? time - lastTimeRef.current : 0.016;
      lastTimeRef.current = time;
      
      const network = networkRef.current;
      if (!network) {
        animationRef.current = requestAnimationFrame(animate);
        return;
      }
      
      // Update growth level
      if (growthLevel !== lastGrowthRef.current) {
        network.setGrowthLevel(growthLevel, time);
        lastGrowthRef.current = growthLevel;
      }
      
      // Calculate effective intensity
      let effectiveIntensity = intensity;
      if (ingestFlash) effectiveIntensity = Math.max(effectiveIntensity, 0.9);
      if (releaseFlash) effectiveIntensity = Math.max(effectiveIntensity, 0.85);
      if (isThinking) effectiveIntensity = Math.max(effectiveIntensity, 0.7);
      
      // Update network state
      network.update(time, deltaTime, effectiveIntensity);
      
      // Render
      const rect = container.getBoundingClientRect();
      ctx.setTransform(window.devicePixelRatio || 1, 0, 0, window.devicePixelRatio || 1, 0, 0);
      renderNetwork(ctx, network, time, effectiveIntensity, rect.width, rect.height, isThinking);
      
      animationRef.current = requestAnimationFrame(animate);
    };
    
    animationRef.current = requestAnimationFrame(animate);
    
    return () => {
      window.removeEventListener('resize', updateSize);
      cancelAnimationFrame(animationRef.current);
    };
  }, [growthLevel, intensity, isThinking, ingestFlash, releaseFlash]);
  
  // Calculate dot position within the orb bounds
  const orbSize = 220 + growthLevel * 20; // Slightly larger for spinning circle
  const dotRange = orbSize * 0.28; // How far the dot can move from center (inside the ring)
  
  return (
    <div 
      ref={containerRef} 
      className="relative w-full h-[350px] md:h-[450px] cursor-pointer"
      onMouseMove={handleMouseMove}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onClick={handleClick}
    >
      {/* Canvas for neural network (behind spinning circles) */}
      <canvas
        ref={canvasRef}
        className="absolute inset-0 w-full h-full pointer-events-none"
        style={{ background: 'transparent' }}
      />
      
      {/* ============================================ */}
      {/* THE SPINNING CIRCLE ORB - Main Visual Element */}
      {/* This IS the orb - not background decoration */}
      {/* ============================================ */}
      <div 
        className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none"
        style={{
          width: `${orbSize}px`,
          height: `${orbSize}px`,
        }}
      >
        {/* Outer spinning ring - SLOW (8s) */}
        <div 
          className="absolute inset-0 rounded-full"
          style={{
            border: '2px solid transparent',
            borderTopColor: 'rgba(6, 182, 212, 0.8)',
            borderRightColor: 'rgba(139, 92, 246, 0.4)',
            animation: 'spin 8s linear infinite',
            filter: `drop-shadow(0 0 ${isHovered ? 12 : 8}px rgba(6, 182, 212, 0.6))`,
          }}
        />
        
        {/* Second spinning ring - MEDIUM (5s, reverse) */}
        <div 
          className="absolute rounded-full"
          style={{
            inset: '15px',
            border: '2px solid transparent',
            borderTopColor: 'rgba(139, 92, 246, 0.7)',
            borderLeftColor: 'rgba(6, 182, 212, 0.3)',
            animation: 'spin 5s linear infinite reverse',
            filter: `drop-shadow(0 0 ${isHovered ? 10 : 6}px rgba(139, 92, 246, 0.5))`,
          }}
        />
        
        {/* Third spinning ring - FAST (3s) */}
        <div 
          className="absolute rounded-full"
          style={{
            inset: '30px',
            border: '1.5px solid transparent',
            borderTopColor: 'rgba(6, 182, 212, 0.6)',
            borderBottomColor: 'rgba(34, 211, 238, 0.3)',
            animation: 'spin 3s linear infinite',
            filter: `drop-shadow(0 0 ${isHovered ? 8 : 5}px rgba(34, 211, 238, 0.4))`,
          }}
        />
        
        {/* Innermost pulsing ring - breathing effect */}
        <div 
          className="absolute rounded-full"
          style={{
            inset: '45px',
            border: '1px solid rgba(6, 182, 212, 0.4)',
            animation: 'pulse 2s ease-in-out infinite',
            boxShadow: `inset 0 0 ${isHovered ? 30 : 20}px rgba(6, 182, 212, 0.15)`,
          }}
        />
        
        {/* Center glow - the "soul" of the orb */}
        <div 
          className="absolute rounded-full"
          style={{
            inset: '55px',
            background: `radial-gradient(circle at center,
              rgba(6, 182, 212, ${isHovered ? 0.25 : 0.15}) 0%,
              rgba(139, 92, 246, ${isHovered ? 0.15 : 0.08}) 40%,
              transparent 70%
            )`,
          }}
        />
        
        {/* Orbiting accent dot on outer ring */}
        <div 
          className="absolute w-2 h-2 rounded-full bg-cyan-400"
          style={{
            top: '50%',
            left: '0',
            transform: 'translate(-50%, -50%)',
            boxShadow: '0 0 8px rgba(6, 182, 212, 0.8), 0 0 16px rgba(6, 182, 212, 0.4)',
            animation: 'spin 8s linear infinite',
            transformOrigin: `${orbSize / 2}px 0`,
          }}
        />
        
        {/* Second orbiting accent dot (opposite side, faster) */}
        <div 
          className="absolute w-1.5 h-1.5 rounded-full bg-purple-400"
          style={{
            top: '50%',
            right: '0',
            transform: 'translate(50%, -50%)',
            boxShadow: '0 0 6px rgba(139, 92, 246, 0.8)',
            animation: 'spin 5s linear infinite reverse',
            transformOrigin: `${-orbSize / 2 + 15}px 0`,
          }}
        />
      </div>
      
      {/* Inner dot that follows mouse - INSIDE the spinning circle */}
      <div 
        className="absolute pointer-events-none z-10"
        style={{
          left: '50%',
          top: '50%',
          transform: `translate(
            calc(-50% + ${(dotPos.x - 0.5) * dotRange}px),
            calc(-50% + ${(dotPos.y - 0.5) * dotRange}px)
          )`,
          transition: 'none',
        }}
      >
        {/* Outer glow */}
        <div 
          className="absolute rounded-full"
          style={{
            width: '50px',
            height: '50px',
            left: '-25px',
            top: '-25px',
            background: `radial-gradient(circle, rgba(6, 182, 212, ${isHovered ? 0.5 : 0.25}) 0%, transparent 70%)`,
            filter: 'blur(10px)',
          }}
        />
        {/* Inner core */}
        <div 
          className="absolute rounded-full"
          style={{
            width: '16px',
            height: '16px',
            left: '-8px',
            top: '-8px',
            background: `radial-gradient(circle at 30% 30%, 
              rgba(255, 255, 255, ${isHovered ? 0.98 : 0.85}) 0%, 
              rgba(6, 182, 212, ${isHovered ? 0.95 : 0.75}) 40%, 
              rgba(139, 92, 246, ${isHovered ? 0.85 : 0.55}) 100%)`,
            boxShadow: `
              0 0 ${isHovered ? 20 : 12}px rgba(6, 182, 212, ${isHovered ? 0.9 : 0.6}),
              0 0 ${isHovered ? 35 : 20}px rgba(139, 92, 246, ${isHovered ? 0.6 : 0.35})
            `,
            transition: 'box-shadow 0.3s ease',
          }}
        />
        {/* White hot center */}
        <div 
          className="absolute rounded-full"
          style={{
            width: '5px',
            height: '5px',
            left: '-2.5px',
            top: '-2.5px',
            background: 'white',
            boxShadow: '0 0 6px white, 0 0 10px rgba(255, 255, 255, 0.5)',
          }}
        />
      </div>
      
      {/* Interaction hint */}
      {showInteractionHint && !isHovered && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none">
          <div className="animate-ping absolute w-24 h-24 -ml-12 -mt-12 rounded-full border border-cyan-400/30" />
        </div>
      )}
      
      {/* Ingest flash ring */}
      {ingestFlash && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div 
            className="absolute rounded-full border-2 border-cyan-400 animate-ping"
            style={{
              width: `${orbSize}px`,
              height: `${orbSize}px`,
            }}
          />
        </div>
      )}
      
      {/* Release flash ring */}
      {releaseFlash && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div 
            className="absolute rounded-full border-2 border-purple-400 animate-pulse"
            style={{
              width: `${200 + growthLevel * 18}px`,
              height: `${200 + growthLevel * 18}px`,
            }}
          />
        </div>
      )}
      
      {/* Status indicator */}
      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 pointer-events-none">
        {isThinking ? (
          <div className="bg-slate-900/80 backdrop-blur-sm px-6 py-3 rounded-full border border-cyan-500/30">
            <div className="flex items-center gap-3">
              <div className="flex gap-1">
                <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                <div className="w-2 h-2 bg-purple-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
              </div>
              <span className="text-sm text-white/90 font-medium">Processing...</span>
            </div>
          </div>
        ) : (
          /* Context Meter - shows progression from spark to full orb */
          <div className="bg-slate-900/70 backdrop-blur-sm px-5 py-3 rounded-full border border-cyan-500/30">
            <div className="flex items-center gap-4">
              <span className="text-xs text-white/50 font-medium">Context</span>
              {/* Visual: Spark → Orb progression */}
              <div className="relative flex items-center gap-2">
                {/* Tiny spark (start - low context) */}
                <div 
                  className="w-2 h-2 rounded-full bg-cyan-400"
                  style={{
                    opacity: growthLevel === 0 ? 1 : 0.3,
                    boxShadow: growthLevel === 0 ? '0 0 6px rgba(6, 182, 212, 0.8)' : 'none',
                  }}
                />
                {/* Progress line */}
                <div className="w-16 h-1 bg-slate-700 rounded-full overflow-hidden">
                  <div 
                    className="h-full bg-gradient-to-r from-cyan-500 via-blue-500 to-purple-500 rounded-full transition-all duration-700 ease-out"
                    style={{ width: `${Math.min(100, growthLevel * 10)}%` }}
                  />
                </div>
                {/* Electric orb (end - full context) */}
                <div 
                  className="rounded-full transition-all duration-500"
                  style={{
                    width: `${8 + growthLevel * 1.5}px`,
                    height: `${8 + growthLevel * 1.5}px`,
                    background: growthLevel >= 8 
                      ? 'radial-gradient(circle, rgba(139, 92, 246, 0.9), rgba(6, 182, 212, 0.7))'
                      : 'radial-gradient(circle, rgba(6, 182, 212, 0.5), transparent)',
                    boxShadow: growthLevel >= 5 
                      ? `0 0 ${growthLevel * 2}px rgba(139, 92, 246, ${growthLevel * 0.08}), 0 0 ${growthLevel * 3}px rgba(6, 182, 212, ${growthLevel * 0.06})`
                      : 'none',
                  }}
                />
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
});

MaxOrbNeural.displayName = 'MaxOrbNeural';

export default MaxOrbNeural;
