import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Send, Mic, MicOff, Volume2, VolumeX, Copy, Check } from 'lucide-react';
import { WordTypewriter } from './TypewriterText';

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: Date;
  isNew?: boolean; // For typing animation
}

interface ChatInterfaceProps {
  onMessage?: (message: string) => void;
  messages?: Message[];
  isTyping?: boolean;
  className?: string;
  voiceEnabled?: boolean;
  onVoiceToggle?: (enabled: boolean) => void;
  demoLimitReached?: boolean;
  onSignupClick?: () => void;
}

// Web Speech API types
interface SpeechRecognitionEvent extends Event {
  results: SpeechRecognitionResultList;
  resultIndex: number;
}

interface SpeechRecognitionResultList {
  length: number;
  item(index: number): SpeechRecognitionResult;
  [index: number]: SpeechRecognitionResult;
}

interface SpeechRecognitionResult {
  isFinal: boolean;
  length: number;
  item(index: number): SpeechRecognitionAlternative;
  [index: number]: SpeechRecognitionAlternative;
}

interface SpeechRecognitionAlternative {
  transcript: string;
  confidence: number;
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  start(): void;
  stop(): void;
  abort(): void;
  onresult: ((event: SpeechRecognitionEvent) => void) | null;
  onerror: ((event: Event & { error?: string }) => void) | null;
  onend: (() => void) | null;
  onstart: (() => void) | null;
}

declare global {
  interface Window {
    SpeechRecognition: new () => SpeechRecognition;
    webkitSpeechRecognition: new () => SpeechRecognition;
  }
}

// Per-message action buttons component
function MessageActions({ 
  content, 
  messageId 
}: { 
  content: string; 
  messageId: string;
}) {
  const [copied, setCopied] = useState(false);
  const [speaking, setSpeaking] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(content);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('[Chat] Copy failed:', err);
    }
  };

  const handleSpeak = () => {
    if (!window.speechSynthesis) {
      console.warn('[Voice] Speech synthesis not supported');
      return;
    }

    // If already speaking this message, stop it
    if (speaking) {
      window.speechSynthesis.cancel();
      setSpeaking(false);
      return;
    }

    // Cancel any other speech first
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(content);
    utterance.rate = 1.0;
    utterance.pitch = 1.0;
    utterance.volume = 1.0;
    
    // Try to find a nice voice
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => 
      v.name.includes('Samantha') || 
      v.name.includes('Daniel') || 
      v.name.includes('Google') ||
      v.lang.startsWith('en')
    );
    if (preferredVoice) {
      utterance.voice = preferredVoice;
    }

    utterance.onstart = () => setSpeaking(true);
    utterance.onend = () => setSpeaking(false);
    utterance.onerror = () => setSpeaking(false);

    window.speechSynthesis.speak(utterance);
  };

  return (
    <div className="flex items-center gap-2 mt-2 opacity-60 sm:opacity-0 group-hover:opacity-100 transition-opacity">
      {/* Copy button - 44px minimum touch target */}
      <button
        onClick={handleCopy}
        aria-label={copied ? 'Copied!' : 'Copy message'}
        className="min-w-[44px] min-h-[44px] p-2 rounded-lg bg-slate-700/50 hover:bg-slate-600/50 transition-colors flex items-center justify-center"
        title={copied ? 'Copied!' : 'Copy message'}
      >
        {copied ? (
          <Check className="w-4 h-4 text-green-400" />
        ) : (
          <Copy className="w-4 h-4 text-white/60 hover:text-white/90" />
        )}
      </button>
      
      {/* Speak button - 44px minimum touch target */}
      <button
        onClick={handleSpeak}
        aria-label={speaking ? 'Stop speaking' : 'Listen to message'}
        className={`min-w-[44px] min-h-[44px] p-2 rounded-lg transition-colors flex items-center justify-center ${
          speaking 
            ? 'bg-cyan-500/30 text-cyan-400' 
            : 'bg-slate-700/50 hover:bg-slate-600/50 text-white/60 hover:text-white/90'
        }`}
        title={speaking ? 'Stop speaking' : 'Listen to message'}
      >
        <Volume2 className={`w-4 h-4 ${speaking ? 'animate-pulse' : ''}`} />
      </button>

      {/* Copied feedback */}
      <AnimatePresence>
        {copied && (
          <motion.span
            initial={{ opacity: 0, x: -10 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0 }}
            className="text-xs text-green-400 ml-1"
          >
            Copied!
          </motion.span>
        )}
      </AnimatePresence>
    </div>
  );
}

export function ChatInterface({ 
  onMessage, 
  messages = [],
  isTyping = false,
  className = '',
  voiceEnabled = true,
  onVoiceToggle,
  demoLimitReached = false,
  onSignupClick
}: ChatInterfaceProps) {
  const [input, setInput] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [speakerOn, setSpeakerOn] = useState(true);
  const [micError, setMicError] = useState<string | null>(null);
  const [micSupported, setMicSupported] = useState(true);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const lastSpokenMessageRef = useRef<string>('');
  const autoSendTimerRef = useRef<NodeJS.Timeout | null>(null);
  const silenceTimerRef = useRef<NodeJS.Timeout | null>(null);
  const lastTranscriptRef = useRef<string>('');
  const [voiceTranscript, setVoiceTranscript] = useState<string>('');

  // Track previous message count to detect new messages
  const prevMessageCountRef = useRef(0);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  
  const scrollToBottom = () => {
    // Method 1: scrollIntoView on the end marker
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    
    // Method 2: Direct scroll to bottom (fallback)
    if (scrollContainerRef.current) {
      const container = scrollContainerRef.current;
      container.scrollTo({
        top: container.scrollHeight,
        behavior: 'smooth'
      });
    }
  };

  // Auto-scroll on new messages (both user and assistant)
  useEffect(() => {
    const currentCount = messages.length;
    const prevCount = prevMessageCountRef.current;
    
    // Scroll when a new message is added (user sends OR assistant replies)
    if (currentCount > prevCount && currentCount > 0) {
      // Immediate scroll attempt
      scrollToBottom();
      // Delayed scroll to ensure DOM has fully updated
      setTimeout(scrollToBottom, 50);
      setTimeout(scrollToBottom, 150);
    }
    
    prevMessageCountRef.current = currentCount;
    
    // Speak the latest assistant message if speaker is on
    if (speakerOn && messages.length > 0) {
      const lastMessage = messages[messages.length - 1];
      if (lastMessage.role === 'assistant' && lastMessage.content !== lastSpokenMessageRef.current) {
        speakText(lastMessage.content);
        lastSpokenMessageRef.current = lastMessage.content;
      }
    }
  }, [messages, speakerOn]);

  // Initialize speech recognition
  useEffect(() => {
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    
    if (!SpeechRecognition) {
      setMicSupported(false);
      return;
    }

    recognitionRef.current = new SpeechRecognition();
    recognitionRef.current.continuous = true; // Keep listening for multi-sentence input
    recognitionRef.current.interimResults = true;
    recognitionRef.current.lang = 'en-US';

    recognitionRef.current.onresult = (event: SpeechRecognitionEvent) => {
      const transcript = Array.from(event.results)
        .map(result => result[0].transcript)
        .join('');
      
      setInput(transcript);
      setVoiceTranscript(transcript);
      lastTranscriptRef.current = transcript;
      setMicError(null);
      
      // Clear any existing silence timer - user is still speaking
      if (silenceTimerRef.current) {
        clearTimeout(silenceTimerRef.current);
        silenceTimerRef.current = null;
      }
      
      // If final result, start auto-send timer with pause tolerance
      if (event.results[event.results.length - 1].isFinal) {
        console.log('[Voice] Final transcript, waiting for more...:', transcript);
        
        // Give 2.5 seconds pause tolerance before auto-sending
        // This lets users pause between sentences without triggering send
        silenceTimerRef.current = setTimeout(() => {
          if (lastTranscriptRef.current.trim()) {
            console.log('[Voice] Auto-sending after pause:', lastTranscriptRef.current);
            // Auto-send
            onMessage?.(lastTranscriptRef.current);
            setInput('');
            setVoiceTranscript('');
            lastTranscriptRef.current = '';
            // Stop recognition after sending
            recognitionRef.current?.stop();
          }
        }, 2500);
      }
    };

    recognitionRef.current.onerror = (event: Event & { error?: string }) => {
      console.error('[Voice] Recognition error:', event);
      setIsListening(false);
      
      // Set user-friendly error message
      const errorType = (event as any).error;
      if (errorType === 'not-allowed') {
        setMicError('Microphone access denied. Please allow mic access.');
      } else if (errorType === 'no-speech') {
        setMicError('No speech detected. Try again.');
      } else if (errorType === 'network') {
        setMicError('Network error. Check your connection.');
      } else {
        setMicError('Mic error. Try again.');
      }
      
      // Clear error after 3 seconds
      setTimeout(() => setMicError(null), 3000);
    };

    recognitionRef.current.onend = () => {
      console.log('[Voice] Recognition ended');
      setIsListening(false);
      
      // If there's a pending transcript and timer, let it complete
      // But if recognition ended without final result, auto-send what we have
      if (lastTranscriptRef.current.trim() && !silenceTimerRef.current) {
        console.log('[Voice] Recognition ended, sending remaining transcript');
        setTimeout(() => {
          if (lastTranscriptRef.current.trim()) {
            onMessage?.(lastTranscriptRef.current);
            setInput('');
            setVoiceTranscript('');
            lastTranscriptRef.current = '';
          }
        }, 500);
      }
    };

    recognitionRef.current.onstart = () => {
      console.log('[Voice] Recognition started');
      setMicError(null);
    };

    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.abort();
      }
      if (autoSendTimerRef.current) {
        clearTimeout(autoSendTimerRef.current);
      }
      if (silenceTimerRef.current) {
        clearTimeout(silenceTimerRef.current);
      }
    };
  }, [onMessage]);

  const speakText = (text: string) => {
    if (!window.speechSynthesis) {
      console.warn('[Voice] Speech synthesis not supported');
      return;
    }

    // Cancel any ongoing speech
    window.speechSynthesis.cancel();

    const utterance = new SpeechSynthesisUtterance(text);
    utterance.rate = 1.0;
    utterance.pitch = 1.0;
    utterance.volume = 1.0;
    
    // Try to find a nice voice
    const voices = window.speechSynthesis.getVoices();
    const preferredVoice = voices.find(v => 
      v.name.includes('Samantha') || 
      v.name.includes('Daniel') || 
      v.name.includes('Google') ||
      v.lang.startsWith('en')
    );
    if (preferredVoice) {
      utterance.voice = preferredVoice;
    }

    console.log('[Voice] Speaking:', text.substring(0, 50) + '...');
    window.speechSynthesis.speak(utterance);
  };

  const toggleListening = () => {
    if (!recognitionRef.current) {
      setMicError('Speech recognition not supported. Try Chrome or Edge.');
      return;
    }

    if (isListening) {
      // Clear any pending auto-send timers
      if (silenceTimerRef.current) {
        clearTimeout(silenceTimerRef.current);
        silenceTimerRef.current = null;
      }
      recognitionRef.current.stop();
      setIsListening(false);
      
      // If there's a transcript, send it immediately when user stops
      if (lastTranscriptRef.current.trim()) {
        console.log('[Voice] User stopped, sending transcript:', lastTranscriptRef.current);
        onMessage?.(lastTranscriptRef.current);
        setInput('');
        setVoiceTranscript('');
        lastTranscriptRef.current = '';
      }
    } else {
      // Stop any ongoing speech before listening
      window.speechSynthesis?.cancel();
      setMicError(null);
      setVoiceTranscript('');
      lastTranscriptRef.current = '';
      
      try {
        recognitionRef.current.start();
        setIsListening(true);
      } catch (error) {
        console.error('[Voice] Failed to start recognition:', error);
        setIsListening(false);
        setMicError('Failed to start mic. Try again.');
      }
    }
  };

  const toggleSpeaker = () => {
    const newState = !speakerOn;
    setSpeakerOn(newState);
    onVoiceToggle?.(newState);
    
    if (!newState) {
      window.speechSynthesis?.cancel();
    }
  };

  const handleSend = () => {
    if (!input.trim()) return;
    
    console.log('[Chat] Sending message:', input);
    onMessage?.(input);
    setInput('');
    inputRef.current?.focus();
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className={`flex flex-col h-full bg-slate-900/50 backdrop-blur-xl rounded-3xl border border-cyan-500/20 overflow-hidden ${className}`}>
      {/* Header */}
      <div className="px-4 md:px-6 py-4 border-b border-cyan-500/20 bg-gradient-to-r from-cyan-500/10 to-purple-500/10">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative">
              <div className="w-3 h-3 bg-green-400 rounded-full animate-pulse" />
              <div className="absolute inset-0 w-3 h-3 bg-green-400 rounded-full animate-ping opacity-75" />
            </div>
            <div>
              <h3 className="font-semibold text-white">Max</h3>
              <p className="text-xs text-white/60">AI Business Enabler</p>
            </div>
          </div>
          
          {/* Voice controls - 44px minimum touch target */}
          {voiceEnabled && (
            <button
              onClick={toggleSpeaker}
              aria-label={speakerOn ? 'Auto-speak ON (click to mute)' : 'Auto-speak OFF (click to unmute)'}
              className={`min-w-[44px] min-h-[44px] p-2.5 rounded-xl transition-all flex items-center justify-center ${
                speakerOn 
                  ? 'bg-cyan-500/20 text-cyan-400 hover:bg-cyan-500/30' 
                  : 'bg-slate-700/50 text-white/40 hover:bg-slate-700'
              }`}
              title={speakerOn ? 'Auto-speak ON (click to mute)' : 'Auto-speak OFF (click to unmute)'}
            >
              {speakerOn ? <Volume2 className="w-5 h-5" /> : <VolumeX className="w-5 h-5" />}
            </button>
          )}
        </div>
      </div>

      {/* Messages */}
      <div 
        ref={scrollContainerRef}
        className="flex-1 overflow-y-auto overflow-x-hidden px-3 md:px-6 py-4 space-y-4 scrollbar-thin scrollbar-thumb-cyan-500/20 scrollbar-track-transparent"
      >
        <AnimatePresence initial={false}>
          {messages.map((message, index) => {
            const isLatestAssistant = message.role === 'assistant' && 
              index === messages.length - 1 && 
              message.isNew;
            
            return (
              <motion.div
                key={message.id}
                initial={{ opacity: 0, y: 20, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                transition={{ duration: 0.3, delay: index * 0.05 }}
                className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div
                  className={`group max-w-[90%] md:max-w-[75%] px-4 md:px-5 py-3 rounded-2xl ${
                    message.role === 'user'
                      ? 'bg-gradient-to-r from-cyan-500 to-blue-500 text-white'
                      : 'bg-slate-800/50 backdrop-blur-sm border border-cyan-500/20 text-white'
                  }`}
                >
                  {/* Fix #11: Format messages with line breaks and bullets */}
                  <div className="text-sm leading-relaxed break-words space-y-2">
                    {isLatestAssistant ? (
                      <WordTypewriter text={message.content} speed={30} />
                    ) : (
                      // Split by newlines and render each line/bullet
                      message.content.split('\n').filter(line => line.trim()).map((line, i) => (
                        <p key={i} className={line.trim().startsWith('•') || line.trim().startsWith('-') ? 'pl-2' : ''}>
                          {line}
                        </p>
                      ))
                    )}
                  </div>
                  <p className="text-xs opacity-60 mt-1">
                    {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </p>
                  
                  {/* Per-message actions for assistant messages */}
                  {message.role === 'assistant' && !isLatestAssistant && (
                    <MessageActions content={message.content} messageId={message.id} />
                  )}
                </div>
              </motion.div>
            );
          })}
        </AnimatePresence>

        {/* Typing indicator */}
        {isTyping && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="flex justify-start"
          >
            <div className="bg-slate-800/50 backdrop-blur-sm px-5 py-3 rounded-2xl border border-cyan-500/20">
              <div className="flex gap-1.5">
                <motion.div
                  animate={{ scale: [1, 1.2, 1] }}
                  transition={{ duration: 0.6, repeat: Infinity, delay: 0 }}
                  className="w-2 h-2 bg-cyan-400 rounded-full"
                />
                <motion.div
                  animate={{ scale: [1, 1.2, 1] }}
                  transition={{ duration: 0.6, repeat: Infinity, delay: 0.2 }}
                  className="w-2 h-2 bg-blue-400 rounded-full"
                />
                <motion.div
                  animate={{ scale: [1, 1.2, 1] }}
                  transition={{ duration: 0.6, repeat: Infinity, delay: 0.4 }}
                  className="w-2 h-2 bg-purple-400 rounded-full"
                />
              </div>
            </div>
          </motion.div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input or Signup CTA */}
      <div className="px-3 md:px-6 py-4 border-t border-cyan-500/20 bg-slate-900/30">
        {demoLimitReached ? (
          /* Demo limit reached - show signup CTA */
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-center py-2"
          >
            <p className="text-white/60 text-sm mb-3">
              🔒 Demo limit reached — {messages.filter(m => m.role === 'user').length} messages
            </p>
            <button
              onClick={onSignupClick}
              className="w-full px-6 py-4 bg-gradient-to-r from-emerald-500 to-cyan-500 rounded-2xl font-semibold text-white hover:shadow-lg hover:shadow-emerald-500/25 transition-all active:scale-95 flex items-center justify-center gap-3"
            >
              <span className="text-lg">🚀</span>
              <span>Sign Up for Full Access</span>
            </button>
            <p className="text-white/40 text-xs mt-2">
              Get unlimited conversations + deploy across your team
            </p>
          </motion.div>
        ) : (
          /* Normal input */
          <div className="flex gap-2 md:gap-3 items-end">
            {/* Microphone button - ENHANCED for clarity */}
            {voiceEnabled && (
              <div className="relative">
                <button
                  onClick={toggleListening}
                  disabled={!micSupported}
                  className={`p-3 md:p-4 rounded-2xl transition-all min-w-[48px] min-h-[48px] flex items-center justify-center ${
                    !micSupported
                      ? 'bg-slate-700/30 text-white/30 cursor-not-allowed'
                      : isListening 
                        ? 'bg-red-500 text-white shadow-lg shadow-red-500/50' 
                        : micError
                          ? 'bg-orange-500/20 border-2 border-orange-500/50 text-orange-400'
                          : 'bg-gradient-to-r from-cyan-500/20 to-blue-500/20 border-2 border-cyan-500/40 text-cyan-400 hover:border-cyan-400 hover:text-cyan-300'
                  }`}
                  title={
                    !micSupported ? 'Mic not supported' :
                    isListening ? 'Click to stop' : 
                    micError ? micError : 
                    'Tap to speak'
                  }
                >
                  {isListening ? (
                    <MicOff className="w-5 h-5 md:w-6 md:h-6" />
                  ) : (
                    <Mic className="w-5 h-5 md:w-6 md:h-6" />
                  )}
                  
                  {/* Pulsing ring when listening */}
                  {isListening && (
                    <>
                      <span className="absolute inset-0 rounded-2xl bg-red-500 animate-ping opacity-30" />
                      <span className="absolute inset-0 rounded-2xl border-2 border-red-400 animate-pulse" />
                    </>
                  )}
                </button>
                
                {/* Label under mic button on mobile */}
                <span className={`absolute -bottom-5 left-1/2 -translate-x-1/2 text-[10px] whitespace-nowrap ${
                  isListening ? 'text-red-400' : micError ? 'text-orange-400' : 'text-white/50'
                }`}>
                  {isListening ? 'Listening...' : micError ? 'Error' : 'Tap to speak'}
                </span>
              </div>
            )}
            
            <input
              ref={inputRef}
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              placeholder={isListening ? 'Listening...' : 'Type your message...'}
              className={`flex-1 min-w-0 bg-slate-800/50 border rounded-2xl px-4 md:px-5 py-3 text-sm text-white focus:outline-none focus:border-cyan-500/50 focus:ring-2 focus:ring-cyan-500/20 transition-all placeholder:text-white/40 ${
                isListening ? 'border-red-500/50 bg-red-500/10' : 'border-cyan-500/20'
              }`}
            />
            <button
              onClick={handleSend}
              disabled={!input.trim()}
              className="px-4 md:px-6 py-3 bg-gradient-to-r from-cyan-500 to-blue-500 rounded-2xl font-medium text-sm disabled:opacity-50 disabled:cursor-not-allowed hover:shadow-lg hover:shadow-cyan-500/25 transition-all active:scale-95 flex items-center gap-2 min-w-[48px] min-h-[48px] justify-center"
            >
              <Send className="w-4 h-4" />
              <span className="hidden md:inline">Send</span>
            </button>
          </div>
        )}
        
        {/* Voice status/error indicator */}
        <AnimatePresence>
          {(isListening || micError) && (
            <motion.div 
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              className={`text-xs mt-3 text-center ${micError ? 'text-orange-400' : 'text-cyan-400'}`}
            >
              {micError ? (
                <span>⚠️ {micError}</span>
              ) : (
                <div className="flex flex-col items-center gap-1">
                  <span className="flex items-center justify-center gap-2">
                    <span className="relative flex h-3 w-3">
                      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-cyan-400 opacity-75" />
                      <span className="relative inline-flex rounded-full h-3 w-3 bg-cyan-500" />
                    </span>
                    <span className="text-cyan-300">Listening... speak naturally</span>
                  </span>
                  {voiceTranscript && (
                    <motion.span 
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      className="text-white/60 italic max-w-[90%] truncate"
                    >
                      "{voiceTranscript}"
                    </motion.span>
                  )}
                  <span className="text-white/40 text-[10px]">Auto-sends after you pause</span>
                </div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}
