import { useEffect, useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Building2, Users, Target, TrendingUp, Briefcase, Brain, MessageCircle } from 'lucide-react';

export interface MindMapNode {
  id: string;
  label: string;
  type: 'company' | 'people' | 'kpi' | 'department' | 'process';
  x?: number;
  y?: number;
  connections?: string[];
}

interface MindMapProps {
  nodes: MindMapNode[];
  className?: string;
}

const iconMap = {
  company: Building2,
  people: Users,
  kpi: Target,
  department: Briefcase,
  process: TrendingUp,
};

const colorMap = {
  company: 'from-cyan-500 to-blue-500',
  people: 'from-purple-500 to-pink-500',
  kpi: 'from-green-500 to-emerald-500',
  department: 'from-orange-500 to-red-500',
  process: 'from-yellow-500 to-amber-500',
};

// Empty state component
function EmptyState() {
  return (
    <div className="absolute inset-0 flex flex-col items-center justify-center text-center px-6">
      <motion.div
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        <div className="w-24 h-24 md:w-32 md:h-32 mx-auto mb-6 rounded-full bg-gradient-to-br from-cyan-500/20 to-purple-500/20 flex items-center justify-center border border-cyan-500/30">
          <Brain className="w-12 h-12 md:w-16 md:h-16 text-cyan-400/60" />
        </div>
        
        <h3 className="text-xl md:text-2xl font-semibold text-white mb-3">
          Building Your Knowledge Graph
        </h3>
        
        <p className="text-white/60 max-w-md mb-6 text-sm md:text-base">
          As we chat, I'll map out your organization, team, goals, and more. 
          Keep talking to help me understand your world better!
        </p>
        
        <div className="flex items-center justify-center gap-2 text-cyan-400/70">
          <MessageCircle className="w-5 h-5" />
          <span className="text-sm">Continue the conversation to build the map</span>
        </div>
        
        {/* Animated dots suggesting activity */}
        <div className="mt-8 flex justify-center gap-2">
          <motion.div
            animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.7, 0.3] }}
            transition={{ duration: 2, repeat: Infinity, delay: 0 }}
            className="w-3 h-3 bg-cyan-500 rounded-full"
          />
          <motion.div
            animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.7, 0.3] }}
            transition={{ duration: 2, repeat: Infinity, delay: 0.3 }}
            className="w-3 h-3 bg-blue-500 rounded-full"
          />
          <motion.div
            animate={{ scale: [1, 1.2, 1], opacity: [0.3, 0.7, 0.3] }}
            transition={{ duration: 2, repeat: Infinity, delay: 0.6 }}
            className="w-3 h-3 bg-purple-500 rounded-full"
          />
        </div>
      </motion.div>
    </div>
  );
}

export function MindMap({ nodes, className = '' }: MindMapProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });

  // Responsive dimensions
  useEffect(() => {
    const updateDimensions = () => {
      if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        setDimensions({
          width: Math.max(300, rect.width),
          height: Math.max(300, rect.height)
        });
      }
    };

    updateDimensions();
    window.addEventListener('resize', updateDimensions);
    return () => window.removeEventListener('resize', updateDimensions);
  }, []);

  // Calculate node positions in a radial layout
  const centerX = dimensions.width / 2;
  const centerY = dimensions.height / 2;
  // Responsive radius - smaller on mobile
  const radius = Math.min(dimensions.width, dimensions.height) * 0.32;

  const positionedNodes = nodes.map((node, index) => {
    if (index === 0) {
      // First node in center
      return { ...node, x: centerX, y: centerY };
    }

    const angle = (2 * Math.PI * (index - 1)) / Math.max(1, nodes.length - 1);
    const x = centerX + radius * Math.cos(angle);
    const y = centerY + radius * Math.sin(angle);
    
    return { ...node, x, y };
  });

  // Responsive node sizes
  const isMobile = dimensions.width < 500;
  const centerNodeSize = isMobile ? 'w-20 h-20' : 'w-32 h-32';
  const outerNodeSize = isMobile ? 'w-14 h-14' : 'w-24 h-24';
  const centerIconSize = isMobile ? 'w-6 h-6' : 'w-10 h-10';
  const outerIconSize = isMobile ? 'w-5 h-5' : 'w-8 h-8';
  const centerTextSize = isMobile ? 'text-[10px]' : 'text-sm';
  const outerTextSize = isMobile ? 'text-[8px]' : 'text-xs';

  return (
    <div 
      ref={containerRef}
      className={`relative w-full h-[400px] md:h-[600px] bg-slate-900/50 backdrop-blur-xl rounded-3xl border border-cyan-500/20 overflow-hidden ${className}`}
    >
      {/* Show empty state if no nodes */}
      {nodes.length === 0 ? (
        <EmptyState />
      ) : (
        <>
          {/* SVG for connections */}
          <svg
            className="absolute inset-0 w-full h-full pointer-events-none"
            viewBox={`0 0 ${dimensions.width} ${dimensions.height}`}
            preserveAspectRatio="xMidYMid meet"
          >
            <defs>
              <linearGradient id="lineGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#06B6D4" stopOpacity="0.3" />
                <stop offset="100%" stopColor="#8B5CF6" stopOpacity="0.3" />
              </linearGradient>
            </defs>
            
            <AnimatePresence>
              {positionedNodes.map((node, index) => {
                if (index === 0) return null; // Skip center node connections
                
                const fromNode = positionedNodes[0]; // Connect all to center
                const toNode = node;
                
                return (
                  <motion.line
                    key={`line-${node.id}`}
                    initial={{ pathLength: 0, opacity: 0 }}
                    animate={{ pathLength: 1, opacity: 1 }}
                    exit={{ pathLength: 0, opacity: 0 }}
                    transition={{ duration: 0.8, delay: index * 0.2 }}
                    x1={fromNode.x}
                    y1={fromNode.y}
                    x2={toNode.x}
                    y2={toNode.y}
                    stroke="url(#lineGradient)"
                    strokeWidth="2"
                    strokeDasharray="5,5"
                  >
                    <animate
                      attributeName="stroke-dashoffset"
                      from="0"
                      to="10"
                      dur="1s"
                      repeatCount="indefinite"
                    />
                  </motion.line>
                );
              })}
            </AnimatePresence>
          </svg>

          {/* Nodes */}
          <AnimatePresence>
            {positionedNodes.map((node, index) => {
              const Icon = iconMap[node.type];
              const isCenter = index === 0;
              
              return (
                <motion.div
                  key={node.id}
                  initial={{ scale: 0, opacity: 0 }}
                  animate={{ scale: 1, opacity: 1 }}
                  exit={{ scale: 0, opacity: 0 }}
                  transition={{
                    type: 'spring',
                    stiffness: 200,
                    damping: 20,
                    delay: index * 0.15,
                  }}
                  className="absolute"
                  style={{
                    left: `${node.x}px`,
                    top: `${node.y}px`,
                    transform: 'translate(-50%, -50%)',
                  }}
                >
                  <div
                    className={`
                      ${isCenter ? centerNodeSize : outerNodeSize}
                      bg-gradient-to-br ${colorMap[node.type]}
                      rounded-full flex flex-col items-center justify-center
                      border-2 md:border-4 border-slate-900 shadow-2xl
                      cursor-pointer hover:scale-110 transition-transform
                    `}
                  >
                    <Icon className={`${isCenter ? centerIconSize : outerIconSize} text-white mb-0.5`} />
                    <span className={`${isCenter ? centerTextSize : outerTextSize} text-white font-semibold text-center px-1 leading-tight`}>
                      {node.label}
                    </span>
                  </div>
                  
                  {/* Pulse effect */}
                  <motion.div
                    className={`absolute inset-0 rounded-full bg-gradient-to-br ${colorMap[node.type]} opacity-30`}
                    animate={{
                      scale: [1, 1.2, 1],
                      opacity: [0.3, 0, 0.3],
                    }}
                    transition={{
                      duration: 2,
                      repeat: Infinity,
                      ease: 'easeInOut',
                    }}
                  />
                </motion.div>
              );
            })}
          </AnimatePresence>
        </>
      )}

      {/* Header */}
      <div className="absolute top-3 left-3 right-3 md:top-4 md:left-4 md:right-4 bg-slate-900/80 backdrop-blur-sm px-4 md:px-6 py-2 md:py-3 rounded-xl md:rounded-2xl border border-cyan-500/30">
        <h3 className="text-white font-semibold text-sm md:text-base">Knowledge Graph</h3>
        <p className="text-white/60 text-xs md:text-sm">
          {nodes.length === 0 
            ? 'Start chatting to build your map'
            : `${nodes.length} element${nodes.length !== 1 ? 's' : ''} discovered`
          }
        </p>
      </div>

      {/* Legend - only show on desktop or when there are nodes */}
      {(nodes.length > 0 || !isMobile) && (
        <div className="absolute bottom-3 right-3 md:bottom-4 md:right-4 bg-slate-900/80 backdrop-blur-sm px-3 md:px-4 py-2 md:py-3 rounded-xl md:rounded-2xl border border-cyan-500/30">
          <div className="flex flex-wrap gap-2 md:gap-3 text-[10px] md:text-xs">
            {Object.entries(colorMap).map(([type, gradient]) => (
              <div key={type} className="flex items-center gap-1 md:gap-2">
                <div className={`w-2 h-2 md:w-3 md:h-3 rounded-full bg-gradient-to-r ${gradient}`} />
                <span className="text-white/80 capitalize">{type}</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
