import { useEffect, useRef, useMemo } from 'react';

// ============================================
// BACKGROUND CONNECTIONS
// Subtle visual of connections/data flowing into the orb
// Atmospheric, not distracting
// ============================================

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  alpha: number;
  targetX: number;
  targetY: number;
  speed: number;
  hue: number;
}

interface Connection {
  startX: number;
  startY: number;
  endX: number;
  endY: number;
  progress: number;
  speed: number;
  hue: number;
  alpha: number;
}

interface BackgroundConnectionsProps {
  className?: string;
  intensity?: number; // 0-1, how active the background is
  orbCenter?: { x: number; y: number }; // Where particles flow to
}

export function BackgroundConnections({ 
  className = '',
  intensity = 0.3,
  orbCenter,
}: BackgroundConnectionsProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>(0);
  const particlesRef = useRef<Particle[]>([]);
  const connectionsRef = useRef<Connection[]>([]);
  const lastTimeRef = useRef<number>(0);

  // Initialize particles
  const particleCount = Math.floor(20 + intensity * 30);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Set up canvas size
    const updateSize = () => {
      const dpr = window.devicePixelRatio || 1;
      const rect = canvas.parentElement?.getBoundingClientRect() || { width: 800, height: 600 };
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      canvas.style.width = `${rect.width}px`;
      canvas.style.height = `${rect.height}px`;
      ctx.scale(dpr, dpr);
    };

    updateSize();
    window.addEventListener('resize', updateSize);

    // Initialize particles at edges
    const initParticles = () => {
      const rect = canvas.getBoundingClientRect();
      const centerX = orbCenter?.x ?? rect.width / 2;
      const centerY = orbCenter?.y ?? rect.height / 2;
      
      particlesRef.current = [];
      
      for (let i = 0; i < particleCount; i++) {
        // Spawn particles from edges
        const edge = Math.floor(Math.random() * 4);
        let x: number, y: number;
        
        switch (edge) {
          case 0: // Top
            x = Math.random() * rect.width;
            y = -10;
            break;
          case 1: // Right
            x = rect.width + 10;
            y = Math.random() * rect.height;
            break;
          case 2: // Bottom
            x = Math.random() * rect.width;
            y = rect.height + 10;
            break;
          default: // Left
            x = -10;
            y = Math.random() * rect.height;
        }

        particlesRef.current.push({
          x,
          y,
          vx: 0,
          vy: 0,
          size: 1 + Math.random() * 2,
          alpha: 0.1 + Math.random() * 0.3,
          targetX: centerX,
          targetY: centerY,
          speed: 0.3 + Math.random() * 0.5,
          hue: 185 + Math.random() * 60, // Cyan to purple range
        });
      }
    };

    initParticles();

    // Animation loop
    const animate = (timestamp: number) => {
      const deltaTime = lastTimeRef.current ? (timestamp - lastTimeRef.current) / 1000 : 0.016;
      lastTimeRef.current = timestamp;

      const rect = canvas.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;
      
      // Clear with fade effect for trails
      ctx.fillStyle = 'rgba(15, 23, 42, 0.1)'; // Match slate-900
      ctx.fillRect(0, 0, rect.width, rect.height);

      const centerX = orbCenter?.x ?? rect.width / 2;
      const centerY = orbCenter?.y ?? rect.height / 2;

      // Update and draw particles
      particlesRef.current.forEach((particle, index) => {
        // Move towards center with some noise
        const dx = centerX - particle.x;
        const dy = centerY - particle.y;
        const dist = Math.sqrt(dx * dx + dy * dy);

        if (dist > 5) {
          // Acceleration towards center
          particle.vx += (dx / dist) * particle.speed * deltaTime * 60;
          particle.vy += (dy / dist) * particle.speed * deltaTime * 60;
          
          // Add some swirl
          const swirl = 0.3;
          particle.vx += -dy / dist * swirl * deltaTime * 30;
          particle.vy += dx / dist * swirl * deltaTime * 30;
          
          // Damping
          particle.vx *= 0.98;
          particle.vy *= 0.98;

          particle.x += particle.vx;
          particle.y += particle.vy;

          // Draw particle with glow
          const gradient = ctx.createRadialGradient(
            particle.x, particle.y, 0,
            particle.x, particle.y, particle.size * 3
          );
          gradient.addColorStop(0, `hsla(${particle.hue}, 80%, 60%, ${particle.alpha * intensity})`);
          gradient.addColorStop(0.5, `hsla(${particle.hue}, 70%, 50%, ${particle.alpha * intensity * 0.5})`);
          gradient.addColorStop(1, 'transparent');

          ctx.fillStyle = gradient;
          ctx.beginPath();
          ctx.arc(particle.x, particle.y, particle.size * 3, 0, Math.PI * 2);
          ctx.fill();

          // Core
          ctx.fillStyle = `hsla(${particle.hue}, 90%, 70%, ${particle.alpha * intensity * 1.5})`;
          ctx.beginPath();
          ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
          ctx.fill();
        } else {
          // Particle reached center - respawn from edge
          const edge = Math.floor(Math.random() * 4);
          switch (edge) {
            case 0:
              particle.x = Math.random() * rect.width;
              particle.y = -10;
              break;
            case 1:
              particle.x = rect.width + 10;
              particle.y = Math.random() * rect.height;
              break;
            case 2:
              particle.x = Math.random() * rect.width;
              particle.y = rect.height + 10;
              break;
            default:
              particle.x = -10;
              particle.y = Math.random() * rect.height;
          }
          particle.vx = 0;
          particle.vy = 0;
          particle.hue = 185 + Math.random() * 60;
        }
      });

      // Randomly create new connections
      if (Math.random() < 0.02 * intensity) {
        const edge = Math.floor(Math.random() * 4);
        let startX: number, startY: number;
        
        switch (edge) {
          case 0:
            startX = Math.random() * rect.width;
            startY = 0;
            break;
          case 1:
            startX = rect.width;
            startY = Math.random() * rect.height;
            break;
          case 2:
            startX = Math.random() * rect.width;
            startY = rect.height;
            break;
          default:
            startX = 0;
            startY = Math.random() * rect.height;
        }

        connectionsRef.current.push({
          startX,
          startY,
          endX: centerX,
          endY: centerY,
          progress: 0,
          speed: 0.5 + Math.random() * 0.5,
          hue: 185 + Math.random() * 60,
          alpha: 0.1 + Math.random() * 0.2,
        });
      }

      // Update and draw connections
      connectionsRef.current = connectionsRef.current.filter(conn => {
        conn.progress += conn.speed * deltaTime;

        if (conn.progress >= 1) {
          return false; // Remove completed connections
        }

        // Draw connection line with gradient
        const currentX = conn.startX + (conn.endX - conn.startX) * conn.progress;
        const currentY = conn.startY + (conn.endY - conn.startY) * conn.progress;
        
        // Trail
        const trailLength = 0.15;
        const trailStart = Math.max(0, conn.progress - trailLength);
        const trailStartX = conn.startX + (conn.endX - conn.startX) * trailStart;
        const trailStartY = conn.startY + (conn.endY - conn.startY) * trailStart;

        const gradient = ctx.createLinearGradient(trailStartX, trailStartY, currentX, currentY);
        gradient.addColorStop(0, 'transparent');
        gradient.addColorStop(0.5, `hsla(${conn.hue}, 80%, 60%, ${conn.alpha * intensity})`);
        gradient.addColorStop(1, `hsla(${conn.hue}, 90%, 70%, ${conn.alpha * intensity * 2})`);

        ctx.strokeStyle = gradient;
        ctx.lineWidth = 1;
        ctx.lineCap = 'round';
        ctx.beginPath();
        ctx.moveTo(trailStartX, trailStartY);
        ctx.lineTo(currentX, currentY);
        ctx.stroke();

        // Bright head
        ctx.fillStyle = `hsla(${conn.hue}, 90%, 80%, ${conn.alpha * intensity * 3})`;
        ctx.beginPath();
        ctx.arc(currentX, currentY, 2, 0, Math.PI * 2);
        ctx.fill();

        return true;
      });

      // Draw subtle center glow
      const centerGlow = ctx.createRadialGradient(
        centerX, centerY, 0,
        centerX, centerY, 150
      );
      centerGlow.addColorStop(0, `hsla(195, 80%, 50%, ${0.05 * intensity})`);
      centerGlow.addColorStop(0.5, `hsla(260, 70%, 40%, ${0.03 * intensity})`);
      centerGlow.addColorStop(1, 'transparent');
      ctx.fillStyle = centerGlow;
      ctx.beginPath();
      ctx.arc(centerX, centerY, 150, 0, Math.PI * 2);
      ctx.fill();

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);

    return () => {
      window.removeEventListener('resize', updateSize);
      cancelAnimationFrame(animationRef.current);
    };
  }, [intensity, orbCenter, particleCount]);

  return (
    <canvas
      ref={canvasRef}
      className={`absolute inset-0 pointer-events-none ${className}`}
      style={{ 
        background: 'transparent',
        mixBlendMode: 'screen',
      }}
    />
  );
}

export default BackgroundConnections;
