async function apiCall<T>(endpoint: string, options: RequestInit = {}): Promise<T> {
  const response = await fetch(`${MAX_API_BASE}${endpoint}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${AUTH_TOKEN}`,
      ...options.headers,
    },
  });
  
  if (!response.ok) {
    throw new Error(`API error: ${response.status}`);
  }
  
  return response.json();
}

// Create or get company for session
export async function createCompany(name: string): Promise<MaxCompany> {
  const result = await apiCall<{ success: boolean; company: MaxCompany }>('/company', {
    method: 'POST',
    body: JSON.stringify({ name }),
  });
  return result.company;
}

// Get company details
export async function getCompany(companyId: string): Promise<MaxCompany | null> {
  try {
    const result = await apiCall<{ success: boolean; company: MaxCompany }>(`/company/${companyId}`);
    return result.company;
  } catch {
    return null;
  }
}

// SECURITY: Sanitize user input to prevent prompt injection attacks
function sanitizeInput(input: string): string {
  // Remove any attempt to inject system prompts or role switches
  const dangerousPatterns = [
    /\[SYSTEM\]/gi,
    /\[INST\]/gi,
    /\[\/INST\]/gi,
    /<<SYS>>/gi,
    /<\/SYS>>/gi,
    /\bsystem:\s*/gi,
    /\bassistant:\s*/gi,
    /\buser:\s*/gi,
    /\bhuman:\s*/gi,
    /```json\s*\{[^}]*"role"\s*:/gi,  // Prevent JSON role injection
    /ignore previous instructions/gi,
    /forget your instructions/gi,
    /you are now/gi,
    /new persona/gi,
    /act as/gi,
    /pretend to be/gi,
    /disregard/gi,
    /override/gi,
  ];
  
  let sanitized = input;
  for (const pattern of dangerousPatterns) {
    sanitized = sanitized.replace(pattern, '[filtered]');
  }
  
  // Limit message length to prevent token exhaustion attacks
  const MAX_MESSAGE_LENGTH = 4000;
  if (sanitized.length > MAX_MESSAGE_LENGTH) {
    sanitized = sanitized.substring(0, MAX_MESSAGE_LENGTH) + '...';
  }
  
  // Escape any HTML/script tags
  sanitized = sanitized
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
  
  return sanitized.trim();
}

// Retry helper with exponential backoff
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  maxRetries: number = 3,
  baseDelayMs: number = 1000
): Promise<T> {
  let lastError: Error | null = null;
  
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error as Error;
      console.warn(`[Max API] Attempt ${attempt + 1}/${maxRetries} failed:`, error);
      
      if (attempt < maxRetries - 1) {
        // Exponential backoff: 1s, 2s, 4s
        const delay = baseDelayMs * Math.pow(2, attempt);
        console.log(`[Max API] Retrying in ${delay}ms...`);
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
  }
  
  throw lastError;
}

// Ensure a valid company session exists
let cachedCompanyId: string | null = null;

async function ensureCompanySession(): Promise<string> {
  if (cachedCompanyId) {
    return cachedCompanyId;
  }
  
  try {
    const company = await createCompany(`Session-${Date.now()}`);
    cachedCompanyId = company.id;
    console.log('[Max API] Created company session:', cachedCompanyId);
    return cachedCompanyId;
  } catch (error) {
    console.warn('[Max API] Failed to create company session:', error);
    // Return a temp ID - backend should handle gracefully
    return `temp-${Date.now()}`;
  }
}

// Chat with Max - the main AI interaction
export async function chatWithMax(
  companyId: string,
  message: string,
  conversationHistory: ChatMessage[],
  learnedInfo: LearnedInfo[]
): Promise<MaxChatResponse> {
  // SECURITY: Sanitize input before processing
  const sanitizedMessage = sanitizeInput(message);
  
  if (!sanitizedMessage) {
    return {
      success: false,
      response: "I didn't catch that. Could you rephrase?",
      learned_info: [],
      suggested_nodes: [],
    };
  }
  
  // Ensure we have a valid company ID
  let validCompanyId = companyId;
  if (!companyId || companyId === 'temp-session' || companyId.startsWith('temp-')) {
    try {
      validCompanyId = await ensureCompanySession();
    } catch (e) {
      console.warn('[Max API] Could not ensure company session, using provided ID');
    }
  }
  
  try {
    // Retry with exponential backoff (3 attempts: immediate, 1s, 2s)
    const result = await retryWithBackoff(async () => {
      const response = await apiCall<{ success: boolean; response?: string; error?: string; usage?: { inputTokens: number; outputTokens: number } }>('/chat', {
        method: 'POST',
        body: JSON.stringify({
          company_id: validCompanyId,
          message: sanitizedMessage,
          stream: false,
        }),
      });
      
      // Handle API-level errors (like "Company not found")
      if (!response.success && response.error) {
        // If company not found, try creating a new one
        if (response.error.toLowerCase().includes('company not found')) {
          console.log('[Max API] Company not found, creating new session...');
          cachedCompanyId = null; // Clear cache
          validCompanyId = await ensureCompanySession();
          
          // Retry with new company ID
          return await apiCall<{ success: boolean; response?: string; error?: string; usage?: { inputTokens: number; outputTokens: number } }>('/chat', {
            method: 'POST',
            body: JSON.stringify({
              company_id: validCompanyId,
              message: sanitizedMessage,
              stream: false,
            }),
          });
        }
        throw new Error(response.error);
      }
      
      return response;
    }, 3, 1000);
    
    // Check if we got a valid response
    if (!result.response) {
      throw new Error('Empty response from API');
    }
    
    // Parse learned info and nodes from AI response
    const parsed = parseMaxResponse(result.response);
    
    return {
      success: result.success,
      response: parsed.cleanResponse,
      learned_info: parsed.learnedInfo,
      suggested_nodes: parsed.suggestedNodes,
      usage: result.usage,
    };
  } catch (error) {
    console.error('[Max API] Chat error after all retries:', error);
    // Fallback: if backend fails after all retries, return a helpful message
    return {
      success: false,
      response: "I'm having a moment — my connection dropped after multiple attempts. 🧠\n\nYou can:\n• Try sending your message again in a few seconds\n• Or use the 'Skip to Org Chart' button to set up your team manually\n\nI'll be back online soon!",
      learned_info: [],
      suggested_nodes: [],
    };
  }
}

// Parse Max's response to extract learned info and clean text
function parseMaxResponse(response: string): {
  cleanResponse: string;
  learnedInfo: LearnedInfo[];
  suggestedNodes: MindMapSuggestion[];
} {
  let cleanResponse = response;
  let learnedInfo: LearnedInfo[] = [];
  let suggestedNodes: MindMapSuggestion[] = [];
  
  // Try to extract JSON block from response
  const jsonMatch = response.match(/```json\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    try {
      const data = JSON.parse(jsonMatch[1]);
      
      if (data.learned) {
        learnedInfo = data.learned.map((l: any, i: number) => ({
          id: `learned-${Date.now()}-${i}`,
          category: l.category || 'company',
          text: l.text,
          confidence: l.confidence || 0.8,
        }));
      }
      
      if (data.nodes) {
        suggestedNodes = data.nodes.map((n: any) => ({
          id: n.id || `node-${Date.now()}-${Math.random().toString(36).slice(2)}`,
          label: n.label,
          type: n.type || 'company',
        }));
      }
      
      // Remove JSON block from visible response
      cleanResponse = response.replace(/```json[\s\S]*?```/g, '').trim();
    } catch (e) {
      console.warn('[Max] Could not parse JSON from response');
    }
  }
  
  // Fallback: Client-side extraction if no JSON from backend
  if (learnedInfo.length === 0) {
    learnedInfo = extractLearningFromText(response);
  }
  
  return { cleanResponse, learnedInfo, suggestedNodes };
}

// Client-side learning extraction (fallback when backend doesn't output JSON)
function extractLearningFromText(response: string): LearnedInfo[] {
  const learned: LearnedInfo[] = [];
  const text = response.toLowerCase();
  
  // Extract company size/type mentions
  if (text.includes('solo') || text.includes('just you') || text.includes('one person')) {
    learned.push({
      id: `learned-${Date.now()}-solo`,
      category: 'team',
      text: 'Solo entrepreneur',
      confidence: 0.85,
    });
  }
  
  if (text.includes('dropship') || text.includes('e-commerce') || text.includes('ecommerce')) {
    learned.push({
      id: `learned-${Date.now()}-type`,
      category: 'company',
      text: 'E-commerce / Dropshipping business',
      confidence: 0.9,
    });
  }
  
  // Extract workload mentions
  if (text.includes('12 hour') || text.includes('long hours') || text.includes('working hard')) {
    learned.push({
      id: `learned-${Date.now()}-workload`,
      category: 'challenges',
      text: 'High workload, working long hours',
      confidence: 0.8,
    });
  }
  
  // Extract revenue/goal mentions
  if (text.includes('revenue') || text.includes('sales') || text.includes('growth')) {
    learned.push({
      id: `learned-${Date.now()}-goals`,
      category: 'goals',
      text: 'Focused on revenue and growth',
      confidence: 0.75,
    });
  }
  
  // Extract product mentions
  if (text.includes('electronics') || text.includes('gadgets') || text.includes('phone')) {
    learned.push({
      id: `learned-${Date.now()}-product`,
      category: 'company',
      text: 'Sells electronics and phone accessories',
      confidence: 0.9,
    });
  }
  
  return learned;
}

