import { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';

interface TypewriterTextProps {
  text: string;
  speed?: number; // ms per character
  onComplete?: () => void;
  className?: string;
  cursor?: boolean;
}

export function TypewriterText({ 
  text, 
  speed = 20, 
  onComplete,
  className = '',
  cursor = true
}: TypewriterTextProps) {
  const [displayText, setDisplayText] = useState('');
  const [isComplete, setIsComplete] = useState(false);
  const indexRef = useRef(0);

  useEffect(() => {
    // Reset when text changes
    setDisplayText('');
    setIsComplete(false);
    indexRef.current = 0;

    if (!text) return;

    const interval = setInterval(() => {
      if (indexRef.current < text.length) {
        // Add characters in small batches for smoother, faster animation
        const charsToAdd = Math.min(3, text.length - indexRef.current);
        setDisplayText(text.slice(0, indexRef.current + charsToAdd));
        indexRef.current += charsToAdd;
      } else {
        clearInterval(interval);
        setIsComplete(true);
        onComplete?.();
      }
    }, speed);

    return () => clearInterval(interval);
  }, [text, speed, onComplete]);

  return (
    <span className={className}>
      {displayText}
      {cursor && !isComplete && (
        <motion.span
          animate={{ opacity: [1, 0, 1] }}
          transition={{ duration: 0.8, repeat: Infinity }}
          className="inline-block w-0.5 h-4 bg-cyan-400 ml-0.5 -mb-0.5"
        />
      )}
    </span>
  );
}

// Word-by-word typewriter for faster content
interface WordTypewriterProps {
  text: string;
  speed?: number; // ms per word
  onComplete?: () => void;
  className?: string;
}

export function WordTypewriter({
  text,
  speed = 50,
  onComplete,
  className = ''
}: WordTypewriterProps) {
  const [displayWords, setDisplayWords] = useState<string[]>([]);
  const [isComplete, setIsComplete] = useState(false);
  const words = text.split(' ');

  useEffect(() => {
    setDisplayWords([]);
    setIsComplete(false);

    if (!text) return;

    let index = 0;
    const interval = setInterval(() => {
      if (index < words.length) {
        setDisplayWords(prev => [...prev, words[index]]);
        index++;
      } else {
        clearInterval(interval);
        setIsComplete(true);
        onComplete?.();
      }
    }, speed);

    return () => clearInterval(interval);
  }, [text, speed, onComplete]);

  return (
    <span className={className}>
      {displayWords.map((word, i) => (
        <motion.span
          key={i}
          initial={{ opacity: 0, y: 5 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.15 }}
          className="inline"
        >
          {word}{i < displayWords.length - 1 ? ' ' : ''}
        </motion.span>
      ))}
      {!isComplete && (
        <motion.span
          animate={{ opacity: [1, 0, 1] }}
          transition={{ duration: 0.8, repeat: Infinity }}
          className="inline-block w-0.5 h-4 bg-cyan-400 ml-0.5 -mb-0.5"
        />
      )}
    </span>
  );
}

// Animated list items
interface TypewriterListProps {
  items: string[];
  speed?: number;
  className?: string;
  itemClassName?: string;
}

export function TypewriterList({
  items,
  speed = 100,
  className = '',
  itemClassName = ''
}: TypewriterListProps) {
  const [visibleItems, setVisibleItems] = useState<number>(0);

  useEffect(() => {
    setVisibleItems(0);
    
    if (!items.length) return;

    let index = 0;
    const interval = setInterval(() => {
      if (index < items.length) {
        setVisibleItems(index + 1);
        index++;
      } else {
        clearInterval(interval);
      }
    }, speed);

    return () => clearInterval(interval);
  }, [items, speed]);

  return (
    <ul className={className}>
      {items.slice(0, visibleItems).map((item, i) => (
        <motion.li
          key={i}
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.3 }}
          className={itemClassName}
        >
          <TypewriterText text={item} speed={15} cursor={false} />
        </motion.li>
      ))}
    </ul>
  );
}
